export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours9Locale { questions: Question[]; }

const questionsFr: Question[] = [
  // ── Marche harmonique (20) ──
  { q:"Qu'est-ce qu'une marche musicale ?", opts:["Un accord répété","Un motif mélodique ou harmonique répété sur différents degrés — transposé progressivement","Une succession de cadences parfaites","Un changement de tempo"], a:1, fb:"Une marche (ou séquence) est un motif répété sur différents degrés : on déplace le motif comme on 'marche' par étapes. Le Canon de Pachelbel est l'exemple classique de marche diatonique." },
  { q:"La différence entre marche diatonique et marche harmonique est :", opts:["La marche diatonique est plus grave","La marche diatonique reste dans la gamme (intervalles ajustés), la marche harmonique transpose exactement (peut quitter la gamme)","Elles sont identiques","La marche harmonique utilise des accords mineurs uniquement"], a:1, fb:"Marche diatonique : le motif s'adapte aux intervalles de la gamme — on reste dans la tonalité. Marche harmonique : transposition exacte des intervalles — on sort de la gamme et on module." },
  { q:"Le Canon de Pachelbel est un exemple de :", opts:["Marche harmonique","Marche diatonique — le motif descend par degrés en restant dans D majeur","Modulation par note commune","Pédale de dominante"], a:1, fb:"Le Canon de Pachelbel déplace le même motif harmonique par degrés successifs en D majeur — c'est une marche diatonique. Les intervalles s'ajustent légèrement pour rester dans la gamme." },
  { q:"Une marche harmonique module car :", opts:["Elle utilise des accords diminués","Elle transpose le motif avec des intervalles exacts — cela force à utiliser des notes hors de la gamme de départ","Elle change le tempo","Elle utilise la gamme chromatique"], a:1, fb:"La marche harmonique préserve les intervalles exacts du motif. Si le motif contient une tierce majeure, chaque transposition aura une tierce majeure exacte — ce qui peut introduire des notes étrangères à la gamme." },
  { q:"La progression Gm–Fm–Ebm–Dbm est une marche :", opts:["Diatonique en G mineur","Harmonique — chaque accord descend d'un ton, même type (mineur), sortant de la gamme","Chromatique","Cadentielle"], a:1, fb:"Gm → Fm → Ebm → Dbm : chaque accord mineur descend d'un ton entier. La progression quitte G mineur après Fm — c'est une marche harmonique descendante par tons." },
  { q:"La marche diatonique de l'Étude op.10 n°3 de Chopin reste dans :", opts:["E mineur","E majeur — le motif se déplace par degrés en restant dans la gamme","C majeur","A mineur"], a:1, fb:"L'Étude op.10 n°3 de Chopin est en E majeur. La marche diatonique de la section A déplace le motif par degrés sans quitter E majeur. Chopin y apporte parfois de légères variantes du modèle." },
  { q:"La marche harmonique est un outil de modulation car :", opts:["Elle est très rapide","Chaque 'étape' de la marche peut être perçue comme une nouvelle escale tonale — la tension s'accumule","Elle évite les cadences","Elle utilise uniquement des accords majeurs"], a:1, fb:"Chaque transposition exacte de la marche harmonique introduit de nouvelles altérations — chaque étape est potentiellement une nouvelle tonalité. La progression est 'voyageuse' : on s'éloigne progressivement du point de départ." },
  { q:"Dans une marche harmonique, la cadence parfaite à l'arrivée sert à :", opts:["Recommencer la marche","Confirmer et ancrer la nouvelle tonalité — signal que le voyage s'achève","Créer une fausse piste","Revenir à la tonalité de départ"], a:1, fb:"Après une marche harmonique qui fait voyager à travers plusieurs tonalités, une cadence parfaite dans la tonalité finale confirme l'arrivée. Sans elle, on resterait dans l'ambiguïté." },
  { q:"La marche harmonique descendante par tons Gm–Fm–Ebm–Dbm se retrouve dans :", opts:["La basse de chaconne uniquement","De nombreux morceaux romantiques et jazz — ex: Misty, nombreuses ballades","Le blues uniquement","Les fugues baroques uniquement"], a:1, fb:"La descente harmonique par tons (cycle de secondes descendantes) est omniprésente en jazz et en musique pop romantique. Elle crée une sensation de 'glissement' harmonique progressif." },
  { q:"La Chaconne de Bach utilise une basse ostinato qui est :", opts:["Une marche harmonique","Une marche diatonique — la basse descend par degrés en restant dans D mineur","Un accord pivot","Une pédale de dominante"], a:1, fb:"La basse de la Chaconne de Bach descend par degrés conjoints dans D mineur — D–C–Bb–A. C'est une marche diatonique à la basse (ostinato), pas une marche harmonique qui modulerait." },
  { q:"Schoenberg distingue marche tonale et marche mélodique car :", opts:["Ce sont des noms différents pour la même chose","La marche tonale adapte les intervalles à la gamme, la marche mélodique peut légèrement modifier le dessin mélodique lui-même","Il n'y a pas de distinction","La marche mélodique est plus grave"], a:1, fb:"Schoenberg note que dans une marche tonale (diatonique), les intervalles s'ajustent mais aussi le dessin mélodique peut légèrement varier pour s'adapter à la gamme. Ces deux notions distinguent le niveau harmonique et mélodique de l'adaptation." },
  { q:"La progression C–G–Am–Em–F–C–Dm–G est une marche :", opts:["Harmonique — elle quitte C majeur","Diatonique — tous les accords appartiennent à C majeur","Chromatique","Directe"], a:1, fb:"C G Am Em F C Dm G : tous ces accords sont diatoniques à C majeur. La progression est une marche diatonique — le motif I–V se transpose sur VI–III puis IV–I, restant en C." },
  { q:"Une marche harmonique ascendante par demi-tons crée :", opts:["Une sensation apaisante","Une tension chromatique intense — chaque étape monte d'un demi-ton","Une progression bleue","Un effet de pédale"], a:1, fb:"La montée chromatique par demi-tons (ex : Cm–C#m–Dm–D#m) crée une tension chromatique progressive très intense. Utilisée par Ravel, Chopin et de nombreux compositeurs pour des effets dramatiques." },
  { q:"La marche harmonique par cycle de quintes descendantes est :", opts:["Une marche diatonique uniquement","La même chose que le cycle des quintes diatoniques — mais en version exacte, modulante","Impossible en pratique","Exclusivement baroque"], a:1, fb:"Le cycle des quintes harmoniques transpose exactement le motif de quinte à chaque étape. Si on reste diatonique, c'est le cycle vu au cours 3. Si on préserve les intervalles exacts, on module — marche harmonique." },
  { q:"La différence sonore entre marche diatonique et marche harmonique est :", opts:["Aucune","La marche diatonique sonne 'à l'intérieur' de la tonalité, la marche harmonique crée une sensation de dérive tonale","La marche harmonique est plus grave","La marche diatonique est plus rapide"], a:1, fb:"La marche diatonique reste dans le 'pays' tonal — l'oreille reconnaît la gamme. La marche harmonique 'dérive' — les intervalles exacts créent des notes étrangères, donnant une sensation de voyage progressif." },
  { q:"Dans l'Étude op.10 n°3, Chopin alterne marche diatonique et :", opts:["Marche chromatique","Marche harmonique à certains endroits — preuve que les deux procédés coexistent","Pédale de basse","Accord napolitain"], a:1, fb:"Dans l'Étude op.10 n°3, Chopin utilise principalement une marche diatonique mais introduit par endroits des transpositions exactes (marche harmonique) pour créer de légères dérives tonales." },
  { q:"Pour utiliser une marche harmonique comme outil de modulation, on :", opts:["Répète la marche indéfiniment","Arrête la marche sur la nouvelle tonalité et la confirme par une cadence parfaite","Ignore les altérations créées","Revient toujours à la tonalité de départ"], a:1, fb:"La marche harmonique transporte vers une nouvelle tonalité à chaque étape. Quand on arrive à la destination souhaitée, on stoppe la marche et on confirme la nouvelle tonalité par une cadence parfaite." },
  { q:"Le pattern I–V–VI–III–IV–I–II–V en C (Canon de Pachelbel) est une marche :", opts:["Harmonique — il module en G","Diatonique — il reste en C tout en déplaçant le motif I–V sur différents degrés","Directe — il saute entre tonalités","Mixte"], a:1, fb:"I–V : C–G. VI–III : Am–Em. IV–I : F–C. II–V : Dm–G. Tout reste dans C majeur. Les degrés de la marche (I, VI, IV, II) sont le point de départ du motif, qui s'adapte à chaque fois à la gamme." },
  { q:"La marche harmonique par tons (Gm–Fm–Ebm) est descendante. Si on la rend ascendante :", opts:["Ce n'est pas possible","On obtient Gm–Am–Bm — une marche ascendante par tons (ou par demi-tons selon l'intervalle choisi)","Elle devient diatonique","Elle devient une pédale"], a:1, fb:"Une marche harmonique peut aller dans les deux sens. Gm–Am–Bm = marche ascendante par tons. Cm–Db–Dm = marche ascendante par demi-tons. La direction crée des effets expressifs différents (tension montante vs descente)." },
  { q:"La marche 'chromatique' (par demi-tons) est une forme de marche :", opts:["Diatonique","Harmonique — les demi-tons exacts forcent à quitter la gamme à chaque étape","Tonale uniquement","Plagale"], a:1, fb:"Une marche par demi-tons transpose le motif d'un demi-ton à chaque fois — même intervalles exacts. C'est une marche harmonique chromatique. Chaque étape introduit de nouvelles altérations." },

  // ── Modulation par note commune (16) ──
  { q:"La modulation par note commune utilise :", opts:["Un accord commun aux deux tonalités","Une seule note identique (note pivot) qui sert de lien entre l'accord de départ et l'accord d'arrivée","Deux accords communs","La sensible artificielle"], a:1, fb:"La modulation par note commune n'utilise pas un accord entier comme pivot, mais une seule note qui appartient aux deux contextes harmoniques. Cette note change de fonction — elle 'glisse' d'un rôle à un autre." },
  { q:"Dans la modulation par note commune, la note pivot est généralement :", opts:["À la basse — effet de pédale","Au soprano — elle attire l'attention et guide l'oreille","Au ténor — voix la plus stable","À l'alto — voix intermédiaire"], a:1, fb:"La note pivot fonctionne mieux au soprano car elle est la plus audible. L'oreille suit la ligne supérieure — quand elle reste immobile pendant que l'harmonie change en dessous, le glissement est fluide et perceptible." },
  { q:"En modulant de G vers Eb avec Sol comme note commune :", opts:["Sol devient la tierce de Eb majeur (Sol est la tierce de Eb = Mi♭–Sol–Si♭)","Sol devient la fondamentale de Eb","Sol devient la sensible de Eb","Sol n'appartient pas à Eb"], a:0, fb:"Sol est la tierce de Eb majeur (Mi♭–Sol–Si♭). En G majeur, Sol est la tonique. Sol comme note commune : tonique de G → tierce de Eb. La même hauteur change de rôle harmonique — modulation fluide." },
  { q:"Les notes les plus courantes pour une modulation par note commune sont :", opts:["La fondamentale et la quinte","La tierce, la septième, la neuvième et la treizième","La sensible uniquement","Les notes de l'accord de dominante"], a:1, fb:"Les notes d'extension (tierce, septième, neuvième, treizième) sont les plus utilisées comme notes communes car elles appartiennent à de nombreux accords dans différentes tonalités." },
  { q:"Si la note commune est à la basse plutôt qu'au soprano, l'effet est :", opts:["Identique","Plus statique — elle agit comme une pédale plutôt que comme une note mélodique conductrice","Plus dramatique","Plus rapide"], a:1, fb:"Une note commune à la basse crée un effet de pédale — l'harmonie change au-dessus d'une basse immobile. Au soprano, elle guide l'oreille mélodiquement. Les deux effets sont valides mais différents." },
  { q:"La modulation par note commune est utilisée par :", opts:["Bach uniquement","Chopin, Liszt, Debussy et le jazz moderne — particulièrement pour les modulations vers des tons éloignés","Mozart uniquement","Le baroque uniquement"], a:1, fb:"Cette technique est caractéristique du romantisme (Chopin, Liszt, Schubert) et de l'impressionnisme (Debussy). En jazz, une note pivot peut être la tierce ou la septième du nouvel accord — réharmonisation." },
  { q:"La modulation par note commune permet d'atteindre :", opts:["Uniquement les tons voisins","Des tonalités éloignées de manière fluide — la note commune crée un lien imperceptible malgré la distance","Uniquement le relatif mineur","La même tonalité (tautologie)"], a:1, fb:"La modulation par note commune est particulièrement utile pour les tonalités éloignées (médiantes, tons à distance de tierce) — l'accord pivot diatonique serait difficile à trouver, mais une seule note suffit." },
  { q:"La modulation vers la médiante (tonalité à une tierce) utilise souvent :", opts:["Un accord pivot diatonique","La note commune — la tierce de l'accord de départ devient la fondamentale ou la tierce de la nouvelle tonalité","Une cadence directe uniquement","Le cycle des quintes"], a:1, fb:"Les modulations par tierces (médiantes) sont idéales pour la note commune : la tierce de l'accord de départ devient souvent une note structurelle de la nouvelle tonalité. Ex : Sol = tierce de C → tonique de G (modulation classique) ou tierce de Eb." },
  { q:"La progression G majeur → Mi♭ majeur avec Sol au soprano illustre :", opts:["Une modulation directe brutale","Une modulation par note commune : Sol = tonique de G → tierce de Eb","Une tonicisation de Eb","Une pédale de tonique"], a:1, fb:"Sol est la tonique de G. Dans Eb majeur (Mi♭–Sol–Si♭), Sol est la tierce. En maintenant Sol au soprano pendant que l'harmonie glisse de G vers Eb, on entend la même note dans deux contextes différents — modulation très fluide." },
  { q:"En jazz, la réharmonisation par note commune consiste à :", opts:["Jouer un accord différent avec la même basse","Garder une note importante (tierce ou septième) de l'accord original dans le nouvel accord de remplacement","Transposer tous les accords","Supprimer la mélodie"], a:1, fb:"En réharmonisation jazz, on remplace un accord en conservant une de ses notes structurelles (souvent la tierce ou la septième) dans le nouvel accord. La continuité mélodique masque le changement harmonique." },
  { q:"La note commune fonctionne particulièrement bien quand elle est :", opts:["Sur un temps faible","Tenue ou répétée — sa durée lui donne le temps de changer de fonction sans rupture","Très courte","Sur le temps le plus faible de la mesure"], a:1, fb:"Une note commune doit être entendue assez longtemps pour que l'oreille l'identifie dans le premier contexte, puis la réinterprète dans le second. Une note trop courte ne permettrait pas cette double perception." },
  { q:"La modulation par note commune diffère de la modulation par accord pivot car :", opts:["L'accord pivot est plus dramatique","La note commune utilise un seul son comme lien (pas un accord entier) — plus subtile, plus utilisée pour les tons éloignés","Elles sont identiques","L'accord pivot est plus récent"], a:1, fb:"L'accord pivot partage un accord entier entre deux tonalités — fonctionne bien pour les tons proches. La note commune partage une seule hauteur — plus flexible, permet d'atteindre des tons très éloignés de manière fluide." },
  { q:"Si Mi est la note commune entre C majeur (tierce) et A mineur (tonique), on peut moduler :", opts:["Uniquement de C vers Am","Dans les deux sens : C→Am (Mi = III de C = I de Am) ou Am→C (Mi = I de Am = III de C)","Uniquement en utilisant G7","Uniquement en mineur harmonique"], a:1, fb:"Une note commune fonctionne dans les deux directions. Mi = III de C et I de Am. On peut donc moduler C→Am (Mi reste, rôle change) ou Am→C (Mi reste, rôle change dans l'autre sens). Même mécanisme, directions opposées." },
  { q:"La modulation par note commune crée une sensation de :", opts:["Rupture dramatique","Glissement imperceptible — l'oreille est guidée par la note tenue pendant que l'harmonie change discrètement","Acceleration rythmique","Instabilité chromatique intense"], a:1, fb:"C'est la grande force de cette technique : le changement harmonique est presque imperceptible grâce à la note maintenue. L'oreille suit le fil conducteur de la note commune et 'glisse' naturellement vers la nouvelle tonalité." },
  { q:"Dans une modulation par note commune, qu'est-ce qui 'bouge' et qu'est-ce qui 'reste' ?", opts:["Tout bouge","L'harmonie bouge (les accords changent), la note commune reste — le fil conducteur","Rien ne bouge — c'est une pédale","La mélodie reste, tout le reste bouge"], a:1, fb:"La note commune est la stabilité dans le changement : elle reste immobile (ou répétée) pendant que toute l'harmonie autour d'elle se transforme. C'est ce contraste entre stabilité et mouvement qui crée la fluidité." },
  { q:"La note commune est parfois appelée 'note pivot' par analogie avec :", opts:["L'accord pivot","La pédale harmonique","Les deux — dans les deux cas, un élément 'pivote' entre deux contextes fonctionnels","L'accord napolitain"], a:2, fb:"Par analogie avec l'accord pivot (un accord entier pivotant entre deux tonalités), la note commune est une 'note pivot' — un seul son qui pivote entre deux contextes. La logique est identique, l'échelle est différente." },

  // ── Modulation par minorisation (14) ──
  { q:"La minorisation d'un accord consiste à :", opts:["Le jouer en mineur sans altérer le contexte tonal","Abaisser la tierce majeure d'un demi-ton pour rendre l'accord mineur — le transformant souvent en pont vers une nouvelle tonalité","Le transposer d'un demi-ton","Le jouer en renversement"], a:1, fb:"La minorisation abaisse la tierce d'un accord majeur pour le rendre mineur. Ex : C (Do–Mi–Sol) → Cm (Do–Mi♭–Sol). Ce nouvel accord mineur peut être réinterprété dans une autre tonalité." },
  { q:"L'effet expressif de la minorisation est :", opts:["De la joie","Une mélancolie subite — l'abaissement de la tierce crée un glissement émotionnel vers l'ombre","De la tension rythmique","De la clarté tonale"], a:1, fb:"La minorisation crée un glissement émotionnel immédiat — la tierce mineure apporte une couleur mélancolique qui contraste avec l'accord majeur précédent. C'est un des effets les plus expressifs de l'harmonie tonale." },
  { q:"Dans la progression C → Cm → F7 → Bb, Cm est :", opts:["Un emprunt à C mineur","La minorisation de C, réinterprétée comme II de Bb majeur — elle initie la modulation vers Bb","Une tonicisation de Bb","Un accord napolitain"], a:1, fb:"C (I de C) → Cm (minorisation, I minorisé) → Cm réinterprété comme IIm de Bb → F7 (V de Bb) → Bb (I de Bb). La minorisation de C le transforme en IIm de Bb — modulation de C vers Bb." },
  { q:"La modulation par minorisation de C vers Bb fonctionne car :", opts:["C et Bb ont la même armure","Cm (Do–Mi♭–Sol) est le IIe degré de Bb majeur (Si♭–Do–Ré–Mi♭–Fa–Sol–La). Cm se réinterprète naturellement dans Bb.","Cm est la dominante de Bb","C et Bb sont à la quinte l'un de l'autre"], a:1, fb:"Cm = Do–Mi♭–Sol. En Bb majeur, le IIe degré = Cm. La minorisation de C (C→Cm) le transforme en IIm de Bb, qui prépare naturellement F7 (V de Bb) puis Bb. Élégant et économique." },
  { q:"La majorisation est l'opération inverse de la minorisation :", opts:["Faux — la minorisation est irréversible","Vrai — on élève la tierce mineure d'un demi-ton pour rendre un accord mineur majeur","Faux — les deux sont identiques","Vrai — mais la majorisation est beaucoup plus fréquente"], a:1, fb:"La majorisation (mineur → majeur) est l'inverse de la minorisation. Elle est moins courante mais existe — ex : Am → A (majeur) peut initier une tonicisation ou une modulation. La minorisation reste plus fréquente expressément." },
  { q:"La progression I → Im est un exemple de :", opts:["Modulation directe","Minorisation de la tonique — très expressive, souvent dans les codas","Emprunt à l'homonyme uniquement","Pédale de dominante"], a:1, fb:"I → Im est une minorisation de la tonique — C → Cm. C'est une des transitions les plus expressives : la tonique elle-même s'assombrit. Très utilisée dans les codas romantiques et les conclusions mélancoliques." },
  { q:"IV → IVm (ex : F → Fm en C majeur) est :", opts:["Un accord napolitain","Un emprunt classique du romantisme — la minorisation de la sous-dominante","Une tonicisation de Fm","Une modulation en C mineur"], a:1, fb:"F → Fm = minorisation du IVe degré. C'est un des emprunts les plus fréquents du romantisme. La couleur sombre du Fm contraste avec F et enrichit la progression. Peut initier une modulation ou rester un simple emprunt." },
  { q:"La minorisation est parfois appelée 'changement modal' car :", opts:["Elle change le tempo","Elle transforme le mode de l'accord (majeur → mineur) — analogie avec le changement de mode d'une gamme","Elle utilise deux armures","Elle change la métrique"], a:1, fb:"La minorisation est un changement de mode local : l'accord passe du mode majeur au mode mineur. C'est analogue à passer d'une gamme majeure à sa parallèle mineure — mais à l'échelle d'un seul accord." },
  { q:"V → Vm est plus rare que I → Im car :", opts:["V mineur n'existe pas","V mineur perd la sensible — Gm n'a pas Si naturel (sensible de C), affaiblissant la tension cadentielle","V mineur est hors tonalité","V mineur est trop grave"], a:1, fb:"Gm (Sol–Si♭–Ré) n'a pas Si naturel — la sensible de C est perdue. Gm a donc moins de tension cadentielle que G ou G7. V → Vm est un affaiblissement de la dominante — rare, mais utilisé pour des effets spécifiques (ex : cadence modale)." },
  { q:"La progression Am–G–F–E7–Am en A mineur illustre :", opts:["Une minorisation","Une majorisation du Ve degré — Em devient E7 (majeur avec 7e) pour créer la sensible G#","Une marche harmonique","Une pédale de dominante"], a:1, fb:"E7 (Mi–Sol#–Si–Ré) est la majorisation-fonctionnalisation du Ve degré de A mineur. En mineur naturel, le Ve serait Em (mineur, sans G#). La mineure harmonique 'majorise' la dominante pour créer la sensible." },
  { q:"La minorisation peut créer une modulation vers :", opts:["Uniquement le relatif mineur","La tonalité dont l'accord minorisé devient un degré fonctionnel naturel — souvent la tonalité une quarte au-dessus","La même tonalité","Uniquement des tons éloignés"], a:1, fb:"La minorisation de C (C→Cm) prépare Bb (Cm = IIm de Bb). En général, l'accord minorisé devient le IIm de la nouvelle tonalité — une quarte au-dessus. Ex : D→Dm prépare Bb... non, prépare C (Dm = IIm de C). Toujours une quarte au-dessus." },
  { q:"Quelle notation indique une minorisation dans un chiffrage d'accords ?", opts:["L'accord suivi de '7'","L'accord suivi de 'm' — ex : C devient Cm","L'accord suivi de 'aug'","L'accord suivi de 'dim'"], a:1, fb:"La minorisation de C s'écrit Cm dans le chiffrage américain. Le 'm' indique que la tierce est abaissée d'un demi-ton. C = Do–Mi–Sol, Cm = Do–Mi♭–Sol." },
  { q:"Dans la progression C–Cm–Bb–F, Cm initie une modulation vers :", opts:["F majeur","Bb majeur — Cm = IIm de Bb, prépare F7 (V de Bb) puis Bb","G mineur","C mineur définitivement"], a:1, fb:"Cm = IIm de Bb majeur. La progression Cm–F7 serait SD–D en Bb, mais ici on a Cm–Bb directement. La modulation vers Bb est amorcée par la minorisation de C." },
  { q:"La minorisation du IVe degré (F → Fm en C) est souvent suivie de :", opts:["G7 directement","C (tonique) pour une cadence plagale mineure","D7","Am"], a:1, fb:"La progression C–Fm–C est une cadence plagale mineure — Fm remplace F comme sous-dominante. C'est un emprunt très expressif. On peut aussi enchaîner vers G7 : C–Fm–G7–C = SD empruntée–D–T." },

  // ── Pédales harmoniques (22) ──
  { q:"Une pédale harmonique est :", opts:["Un accord répété sans changer","Une note tenue ou répétée pendant que les autres voix changent d'accords","Un accord de dominante fixe","Un ornement mélodique"], a:1, fb:"La pédale harmonique est une note maintenue (tenue ou répétée) dans une voix pendant que les harmonies changent autour d'elle. Elle peut appartenir aux accords qui passent ou leur être étrangère — créant alors des dissonances." },
  { q:"La pédale de tonique crée :", opts:["De la tension maximale","De la stabilité — elle ancre le centre tonal en maintenant la fondamentale de la tonique","Une modulation","Une suspension"], a:1, fb:"La pédale de tonique maintient le Ier degré (Do en C) pendant que l'harmonie évolue. Elle ancre le centre tonal — l'oreille ne perd jamais le fil de la tonique. Souvent utilisée en début ou fin de mouvement." },
  { q:"La pédale de dominante prépare :", opts:["Une nouvelle tonalité","La cadence finale — la dominante tenue crée une tension prolongée qui amplifie la résolution sur I","Une pédale de tonique","Un accord napolitain"], a:1, fb:"La pédale de dominante maintient Sol (en C) pendant que les accords changent au-dessus. Cette tension prolongée rend la résolution finale sur C d'autant plus satisfaisante. Très utilisée avant les grandes cadences." },
  { q:"La double pédale maintient simultanément :", opts:["Deux fondamentales quelconques","Les deux pôles tonaux — tonique et dominante (Do et Sol en C)","La tierce et la quinte","Deux dominantes secondaires"], a:1, fb:"La double pédale maintient simultanément I et V — Do et Sol en C. Elle ancre les deux pôles fondamentaux de la tonalité, créant une base très stable pour des harmonies mouvantes au-dessus." },
  { q:"La pédale de soprano est caractéristique de :", opts:["La musique baroque uniquement","La musique du XIXe siècle et l'impressionnisme (Debussy, Ravel)","La fugue uniquement","Le jazz moderne uniquement"], a:1, fb:"La pédale de soprano — note tenue dans la voix supérieure — est particulièrement développée dans le romantisme et l'impressionnisme. Debussy l'utilise abondamment pour créer des effets de suspension et d'ambiguïté harmonique." },
  { q:"Une pédale est 'étrangère' quand :", opts:["Elle est jouée fort","Elle ne fait pas partie de l'accord qui passe au-dessus — elle crée une dissonance temporaire","Elle est très grave","Elle dure une seule mesure"], a:1, fb:"Une pédale étrangère (ou 'pédal note' en anglais) ne fait pas partie de l'accord en cours — elle créé une dissonance. Cette dissonance est résolue quand un accord contenant la pédale arrive. L'effet de tension est expressif." },
  { q:"La progression C–Am–F–G avec Do tenu à la basse est une pédale de :", opts:["Dominante","Tonique — Do est le Ier degré de C, il reste à la basse pendant toute la progression","Double pédale","Pédale de soprano"], a:1, fb:"Do est la tonique de C majeur. Maintenu à la basse pendant Am, F et G (qui ne contiennent pas tous Do comme fondamentale), il crée une pédale de tonique. L'effet ancre C comme centre pendant l'évolution harmonique." },
  { q:"La progression Dm–G7–C avec Sol tenu à la basse est une pédale de :", opts:["Tonique","Dominante — Sol est le Ve degré de C. Il reste immobile pendant que Dm et G7 passent","Double pédale","Pédale de soprano"], a:1, fb:"Sol est la dominante de C. Maintenu à la basse pendant Dm et G7, il crée une pédale de dominante. La tension est maximale — Sol ne résout sur Do qu'à la fin. Très utilisé avant les grandes cadences." },
  { q:"La pédale de tonique est souvent utilisée :", opts:["Au milieu d'un développement tendu","En début ou fin de pièce — pour stabiliser et ancrer le centre tonal","Uniquement en mineur","Pour moduler"],  a:1, fb:"La pédale de tonique est un outil de stabilisation — elle est naturelle en début de pièce (pour établir la tonalité) ou en fin (pour la confirmer définitivement). Au milieu, elle peut créer un effet de repos ou de point d'orgue." },
  { q:"Qu'est-ce qui distingue une pédale d'un accord répété ?", opts:["Rien — c'est la même chose","Dans une pédale, une seule note est tenue pendant que les autres voix changent librement. Un accord répété répète toutes ses notes ensemble.","La pédale est toujours plus grave","L'accord répété est toujours fortissimo"], a:1, fb:"La pédale = une note immobile, harmonies changeantes autour. Accord répété = toutes les notes de l'accord se répètent ensemble. La pédale maintient une continuité mélodique dans une voix pendant le changement harmonique." },
  { q:"Dans la forme musicale, la pédale de dominante est souvent utilisée :", opts:["Au début d'une pièce","Avant la récapitulation dans une forme sonate — elle crée l'attente du retour à la tonique","Dans le développement uniquement","À la fin d'une pièce seulement"], a:1, fb:"Dans la forme sonate, la pédale de dominante précède souvent la récapitulation — la dominante tenue pendant plusieurs mesures crée une attente intense du retour au thème principal en tonique. Effet dramatique très efficace." },
  { q:"La pédale peut être :", opts:["Uniquement à la basse","Dans n'importe quelle voix — basse, soprano, alto ou ténor","Uniquement au soprano","Uniquement dans les voix intermédiaires"], a:1, fb:"La pédale peut occuper n'importe quelle voix. La basse est la plus fréquente (pédales de tonique et de dominante). Le soprano est utilisé pour des effets de suspension et d'impressionnisme. Les voix intérieures sont plus rares mais possibles." },
  { q:"Une double pédale (Do + Sol) crée un effet de :", opts:["Modulation vers G","Ambiguïté tonale — les deux pôles sont maintenus, permettant des harmonies libres","Cadence parfaite prolongée","Accord diminué"], a:1, fb:"La double pédale Do–Sol maintient simultanément la tonique et la dominante — les deux fondamentaux de la tonalité. Au-dessus, l'harmonie peut s'aventurer librement sans perdre le fil tonal. Effet de stabilité et d'ambiguïté simultanées." },
  { q:"La pédale de dominante crée des dissonances car :", opts:["La note Sol ne s'entend pas bien","Les accords qui passent au-dessus (IV, II) contiennent des notes qui 'frottent' avec Sol","Les voix se croisent","La sensible n'est pas résolue"], a:1, fb:"Sol (pédale) + F majeur au-dessus = Sol + Fa + La + Do. Sol et Fa sont distants d'une 7e — dissonance. Sol + Dm = Sol + Ré + Fa + La. Ces dissonances créent la tension qui sera résolue sur C avec Sol dans l'accord." },
  { q:"Chopin utilise souvent la pédale de :", opts:["Soprano uniquement","Dominante dans ses nocturnes — la basse tient Sol pendant que l'harmonie évolue richement","Tonique uniquement","Double pédale uniquement"], a:1, fb:"Les Nocturnes de Chopin utilisent fréquemment la pédale de dominante à la basse gauche (souvent en octave) pendant que la main droite joue des harmonies complexes et ornées. L'effet est très romantique." },
  { q:"La pédale de soprano est particulièrement utilisée dans :", opts:["Les fugues baroques","L'impressionnisme (Debussy, Ravel) — elle crée des accords appogiaturés et des harmonies suspendues","Le blues uniquement","La forme sonate classique"], a:1, fb:"Debussy et Ravel utilisent abondamment la pédale de soprano — souvent la dominante ou la médiante — pour créer des harmonies flottantes et ambiguës caractéristiques de leur style impressionniste." },
  { q:"La progression G7–C où Sol est tenu à la basse pendant C est :", opts:["Une pédale de dominante","Une pédale de tonique — Sol est la quinte de C, qui reste après que G7 ait résolu","Une double pédale","Une pédale étrangère"], a:1, fb:"Quand G7 résout sur C, Sol (basse) peut rester — Sol est la quinte de C. Ce Sol tenu est maintenant une pédale de quinte (ou de dominante maintenue). Il ne crée pas de dissonance dans C mais donne une couleur de I6/4." },
  { q:"La pédale de dominante dans une fugue de Bach est souvent :", opts:["Une seule mesure","Une longue tenue de plusieurs mesures à la basse avant la strette ou la cadence finale","Un ornement rapide","Une note répétée au soprano"], a:1, fb:"Dans les fugues de Bach, la pédale de dominante (pédale d'orgue) est souvent un Sol tenu sur plusieurs mesures à la basse, pendant que les voix supérieures s'agitent. C'est une technique caractéristique de l'écriture fuguée." },
  { q:"Le terme 'pédale d'orgue' vient de :", opts:["La pédale de tempo","Le clavier de pédale de l'orgue — l'instrumentiste peut tenir une note au pied pendant que les mains jouent d'autres harmonies","Les pédales d'expression","Les pédales du piano"], a:1, fb:"L'orgue possède un clavier de basse joué aux pieds (le pédalier). L'organiste peut tenir une note au pied pendant que les deux mains jouent librement. Cette technique a inspiré le concept de pédale harmonique dans toute la composition." },
  { q:"Quelle pédale est la plus rare dans l'écriture classique ?", opts:["Pédale de tonique","Pédale de dominante","Pédale intérieure (voix intermédiaire tenue)","Double pédale"], a:2, fb:"La pédale dans une voix intérieure (alto ou ténor) est la plus rare — difficile à percevoir et à gérer techniquement. Les pédales de basse et de soprano sont beaucoup plus fréquentes car elles occupent les registres extrêmes, plus audibles." },
  { q:"Dans une double pédale Do–Sol, laquelle des deux est la plus grave ?", opts:["Sol","Do — Do3 est plus grave que Sol3","Elles sont au même octave","Cela dépend des voix"], a:1, fb:"Do3 (octave 3) est plus grave que Sol3. Dans une double pédale classique à la basse, Do est souvent à la basse et Sol une quinte au-dessus — ou Do et Sol à l'octave (Do3 et Do4, Sol2 et Sol3)." },
  { q:"La pédale de tonique en fin de pièce crée un effet de :", opts:["Surprise","Conclusion et stabilisation définitive — la tonique maintenue pendant les derniers accords confirme le centre tonal","Tension maximale","Modulation vers le relatif"], a:1, fb:"En fin de pièce, la pédale de tonique (souvent avec un accord de C tenu à la basse pendant les derniers accords) crée un sentiment de conclusion inévitable. Le centre tonal est ancré — l'oreille sait que la pièce se termine ici." },

  // ── Accords appogiaturés (20) ──
  { q:"Un accord appogiaturé est :", opts:["Un accord joué forte","Un accord étranger inséré brièvement avant un accord réel, dont il prépare la résolution par dissonance","Un accord renversé","Un accord de dominante secondaire"], a:1, fb:"L'accord appogiaturé est l'équivalent harmonique de la note d'appogiature — une dissonance harmonique entière qui se résout sur un accord réel. Il est étranger à la fonction en cours et crée une tension brève mais intense." },
  { q:"La différence entre accord appogiaturé et accord de passage est :", opts:["Aucune différence","L'accord appogiaturé est sur un temps fort et crée une dissonance forte. L'accord de passage est sur un temps faible et relie deux accords réels","L'accord de passage est plus grave","L'accord appogiaturé dure plus longtemps"], a:1, fb:"L'accord appogiaturé est sur un temps fort (comme la note d'appogiature) et crée une dissonance accentuée. L'accord de passage est sur un temps faible et relie fluidement deux harmonies réelles." },
  { q:"L'accord de dominante sur tonique (ex : G7/C) est :", opts:["Un accord de tonique","Un accord appogiaturé — G7 posé sur une basse de tonique, créant une dissonance qui retarde la résolution finale","Un accord de passage","Un accord pivot"], a:1, fb:"G7/C = Sol–Si–Ré–Fa avec Do à la basse. L'accord exprime une tension de dominante (G7) mais le Do à la basse empêche la résolution — Do est la tonique, pas Sol. C'est un retard harmonique de la résolution." },
  { q:"En C majeur, G7/C résout sur :", opts:["G majeur","C majeur — la dissonance de dominante se résout normalement sur la tonique","Dm","Am"], a:1, fb:"G7/C crée une tension de dominante sur basse de tonique. La résolution naturelle est C majeur — les voix résolvent normalement (Si→Do, Fa→Mi) et la basse Do reste immobile. La dissonance est résolue." },
  { q:"L'accord de dominante sur tonique est qualifié de 'retard harmonique' car :", opts:["Il est très lent","Il retarde l'arrivée de l'accord de tonique réel — la basse de tonique est déjà là mais l'accord de dominante crée encore de la tension","Il est plus grave","Il utilise la septième majeure"], a:1, fb:"Dans G7/C, la basse Do est la tonique — elle est 'là' — mais l'accord de dominante au-dessus crée encore de la tension. C'est comme si la résolution était amorcée (basse) mais pas encore complète (accord). Effet de suspense harmonique." },
  { q:"Les accords appogiaturés sont fréquents dans :", opts:["Le baroque strict uniquement","Le romantisme et l'impressionnisme — pour la richesse expressive des dissonances retardées","Le blues uniquement","La musique médiévale"], a:1, fb:"Le romantisme (Chopin, Liszt, Wagner) et l'impressionnisme (Debussy, Ravel) exploitent abondamment les accords appogiaturés — dissonances expressives qui amplifient la tension avant résolution. Langage harmonique riche et coloré." },
  { q:"Un accord appogiaturé crée de la tension car :", opts:["Il est joué fort","Il est étranger à la fonction harmonique en cours — sa dissonance appelle une résolution","Il est en renversement","Il est mineur"], a:1, fb:"L'accord appogiaturé introduit des notes étrangères à l'accord attendu. Cette dissonance crée une tension qui demande résolution — exactement comme une note d'appogiature, mais à l'échelle d'un accord entier." },
  { q:"La résolution d'un accord appogiaturé se fait :", opts:["Par un saut de quinte","Par des mouvements conjoints des voix vers les notes de l'accord réel","Par un saut de tierce","Par la basse uniquement"], a:1, fb:"Les voix de l'accord appogiaturé se résoudent conjointement (par degrés) vers les notes de l'accord réel. Ex : dans G7/C → C, les voix Sol–Si–Ré–Fa glissent vers Do–Mi–Sol (accord C). La basse Do reste immobile." },
  { q:"L'accord appogiaturé est sur :", opts:["Un temps faible","Un temps fort — comme la note d'appogiature, sa force vient de sa position accentuée","Toujours sur la levée","Après la barre de mesure"], a:1, fb:"L'accord appogiaturé, comme la note d'appogiature, est placé sur un temps fort. Sa position accentuée amplifie la dissonance — l'oreille s'y attarde davantage avant que la résolution n'arrive." },
  { q:"La progression G7/C → C peut s'analyser comme :", opts:["Une cadence imparfaite","Un accord de dominante appogiaturé → résolution sur la tonique — retard harmonique du Ier degré","Une tonicisation de G","Un emprunt à G majeur"], a:1, fb:"G7/C est V7 sur basse de I — l'accord appogiaturé de dominante sur tonique. La résolution G7/C → C est un retard harmonique : la basse Do était déjà là, l'accord de dominante se lève pour révéler l'accord de C pur." },
  { q:"Quel compositeur est célèbre pour ses accords appogiaturés dans ses sonates ?", opts:["Bach","Beethoven — ses accords de V sur pédale de I sont très caractéristiques dans les codas","Haydn uniquement","Scarlatti"], a:1, fb:"Beethoven utilise fréquemment des accords de V sur pédale de I (G7/C, D7/G etc.) dans ses codas et transitions — effet très dramatique qui retarde la résolution finale et amplifie l'impact de la cadence parfaite." },
  { q:"La notation G7/C signifie :", opts:["G7 transposé en C","Accord G7 (Sol–Si–Ré–Fa) avec Do à la basse — le slash indique la note de basse","G et C joués ensemble","G7 suivi de C"], a:1, fb:"La notation X/Y = accord X avec Y à la basse. G7/C = accord de Sol septième de dominante (Sol–Si–Ré–Fa) avec Do (Do) à la basse. Le Do est étranger à l'accord G7 — c'est ce qui crée la dissonance appogiaturée." },
  { q:"Un accord appogiaturé peut :", opts:["Être n'importe quel accord","Être un accord de n'importe quelle fonction posé sur une basse étrangère à cet accord","Uniquement être une dominante sur tonique","Uniquement être en position fondamentale"], a:1, fb:"En principe, n'importe quel accord peut être appogiaturé — IV/I, II/I, etc. Le cas le plus classique et expressif reste V7/I (dominante sur basse de tonique), mais la technique s'applique plus largement." },
  { q:"La différence entre pédale et accord appogiaturé est :", opts:["Aucune différence","La pédale maintient une note dans une voix pendant que les accords changent. L'accord appogiaturé est un accord entier étranger qui précède et se résout sur un accord réel.","La pédale est toujours à la basse","L'accord appogiaturé dure plus longtemps"], a:1, fb:"Pédale : une note immobile (dans une voix), harmonies changeantes autour. Accord appogiaturé : un accord entier étranger, ponctuel, sur un temps fort, qui se résout sur l'accord réel. Deux phénomènes différents, quoique liés." },
  { q:"Dans G7/C, le Do à la basse est :", opts:["La septième de G7","La fondamentale de C (tonique) placée à la basse — étranger à l'accord G7 au-dessus","La quinte de G","La sensible de C"], a:1, fb:"G7 = Sol–Si–Ré–Fa. Do n'est pas dans G7 — c'est la fondamentale de C. Placé à la basse, Do crée la dissonance : l'accord G7 flotte au-dessus de la basse 'tonique', créant l'accord appogiaturé." },
  { q:"L'effet musical de G7/C → C est similaire à :", opts:["Une cadence rompue","Un retard — comme si la résolution sur Do était annoncée par la basse (déjà Do) mais retardée par l'accord de dominante encore présent","Une modulation","Une cadence plagale"], a:1, fb:"G7/C → C est analogue à un retard mélodique : la basse 'annonce' Do, mais l'accord de dominante crée encore de la tension. Quand G7/C se résout en C pur, la résolution est complète — effet de 'délivrance' harmonique." },
  { q:"La pédale de soprano crée souvent des accords :", opts:["Parfaits","Appogiaturés — la note tenue au soprano devient étrangère aux accords changeant sous elle","Diminués uniquement","De septième majeure"], a:1, fb:"La pédale de soprano, tenue pendant que les accords changent sous elle, crée naturellement des accords appogiaturés — la note fixe est étrangère aux accords changeants. Cet effet est très caractéristique de l'écriture impressionniste." },
  { q:"Dans une coda romantique, G7/C → C est souvent précédé de :", opts:["Dm uniquement","Une longue pédale de dominante ou un 6/4 de cadence — pour amplifier encore plus la tension finale","Am","Une modulation en G"], a:1, fb:"La séquence I6/4 → G7/C → C (ou Dm–I6/4–G7/C–C) est une accumulation de tensions : 6/4 prépare G7/C qui est lui-même un retard de C. La résolution finale sur C pur est d'autant plus satisfaisante." },
  { q:"Peut-on avoir un accord appogiaturé de tonique (I) sur basse de dominante ?", opts:["Non — uniquement V sur I","Oui — C/G (Do–Mi–Sol sur basse Sol) est le 2e renversement de I, parfois analysé comme I appogiaturé sur V","Non — la tonique ne peut pas être appogiaturée","Seulement en mineur"], a:1, fb:"C/G peut être analysé comme I6/4 = accord de I en 2e renversement, avec Sol (dominante) à la basse. C'est le 6/4 de cadence — un accord de tonique 'appogiaturé' sur la basse de dominante, qui se résout vers V7–I." },
  { q:"Le terme 'accord d'appogiature' vient de :", opts:["L'italien 'appoggiare' (s'appuyer) — l'accord s'appuie sur un accord réel avant de se résoudre","Le latin 'apparatus'","L'allemand 'Aufsatz'","Le grec 'apoggios'"], a:0, fb:"'Appoggiare' en italien signifie 's'appuyer'. L'appoggiature (note ou accord) s'appuie lourdement sur un temps fort avant de se résoudre. Le terme reflète cette idée de poids expressif et de tension accentuée." },

  // ── Synthèse (16) ──
  { q:"Parmi ces quatre techniques, laquelle peut moduler vers des tons très éloignés le plus facilement ?", opts:["Accord pivot diatonique","Marche harmonique ou note commune — les deux peuvent atteindre des tons éloignés","Minorisation uniquement","Pédale de dominante"], a:1, fb:"L'accord pivot diatonique fonctionne bien pour les tons proches (voisins). La marche harmonique et la note commune sont plus flexibles — elles peuvent atteindre des tons éloignés (médiantes, tierces) de manière fluide." },
  { q:"La progression C–Cm–Bb–F7–Bb utilise :", opts:["Une pédale de tonique","Une minorisation de C (C→Cm) qui initie la modulation vers Bb","Un accord napolitain","Une marche diatonique"], a:1, fb:"C→Cm = minorisation. Cm = IIm de Bb. F7 = V de Bb. Bb = I de Bb. C'est la séquence de modulation par minorisation : I de C (minorisé) → IIm de Bb → V de Bb → I de Bb." },
  { q:"La progression C–Am–F–G avec Do tenu à la basse ET Sol tenu au soprano est :", opts:["Une pédale de tonique","Une double pédale — Do à la basse (tonique) et Sol au soprano (dominante)","Un accord appogiaturé","Une marche diatonique"], a:1, fb:"Do à la basse + Sol au soprano tenu = double pédale (tonique + dominante). L'harmonie Am–F–G évolue librement entre ces deux pôles immobiles." },
  { q:"La marche harmonique C–G–Am–Em (puis répétition à la quinte inférieure) est :", opts:["Une marche harmonique — elle module","Une marche diatonique — la répétition à la quinte inférieure reste dans C majeur (F–C–Dm–Am)","Une pédale de dominante","Une tonicisation"], a:1, fb:"Si la répétition adapte les intervalles à la gamme (F–C–Dm–Am en C), c'est une marche diatonique. Si elle transpose exactement (F#–C#–D#m–A#m), ce serait harmonique et modulerait. La première option reste diatonique." },
  { q:"Dans une progression avec pédale de dominante, les accords qui créent le plus de dissonance sont :", opts:["I et V","IV et II — ils contiennent des notes qui frottent avec la pédale de Sol","III et VI","VII et III"], a:1, fb:"Pédale Sol + Fa majeur (F) au-dessus = Sol + Fa–La–Do. Sol et Fa sont une septième mineure — dissonance. Pédale Sol + Ré mineur (Dm) = Sol + Ré–Fa–La. Sol et Fa encore. IV et II créent les dissonances les plus fortes avec une pédale de dominante." },
  { q:"La progression Gm–Fm–Ebm–Dbm peut moduler vers :", opts:["G majeur","Db mineur ou la tonalité dont Dbm est un degré — après Dbm, une cadence parfaite confirme","C majeur uniquement","Uniquement les tons voisins de G"], a:1, fb:"La marche harmonique Gm–Fm–Ebm–Dbm s'arrête sur Dbm. Si on confirme Db (majeur ou mineur) par une cadence parfaite (Ab7–Dbm ou Ab–Db), la modulation vers Db est établie. La marche a servi de transition." },
  { q:"Quel outil crée la modulation la plus imperceptible ?", opts:["La marche harmonique","La modulation par note commune — une seule note reste, le changement est presque inaudible","La minorisation","La modulation directe"], a:1, fb:"La note commune maintenue au soprano pendant le changement harmonique crée la transition la plus fluide — l'oreille suit le fil de la note tenue et 'glisse' naturellement vers la nouvelle tonalité sans rupture perceptible." },
  { q:"L'accord G7/C suivi de C est souvent précédé de :", opts:["Un accord de F uniquement","Dm, F, ou tout accord de SD — pour la séquence SD–appogiaturé–T","G majeur","Am uniquement"], a:1, fb:"La séquence SD → G7/C → C est très fréquente : Dm (ou F) prépare la dominante appogiaturée G7/C qui se résout sur C. On peut aussi enchaîner I6/4 → G7/C → C pour une cadence encore plus élaborée." },
  { q:"La pédale de tonique au début d'une pièce sert à :", opts:["Créer de la tension","Établir clairement la tonalité dès le début — l'auditeur s'ancre dans le nouveau centre tonal","Moduler rapidement","Créer une ambiguïté tonale"], a:1, fb:"Une pédale de tonique en ouverture établit immédiatement et sans ambiguïté la tonalité principale. Bach et Händel utilisent souvent cette technique dans leurs préludes et ouvertures pour ancrer la tonalité dès les premières mesures." },
  { q:"La modulation par minorisation est parfois appelée 'chromatisme fonctionnel' car :", opts:["Elle utilise la gamme chromatique entière","L'altération (abaissement de la tierce) est chromatique mais fonctionnellement justifiée — elle sert à changer de tonalité","Elle est très rapide","Elle utilise uniquement des demi-tons"], a:1, fb:"'Chromatisme fonctionnel' : le Mi♭ (abaissement de Mi dans C→Cm) est une altération chromatique (Mi → Mi♭, un demi-ton). Mais ce chromatisme est fonctionnel — il sert à réinterpréter l'accord dans une nouvelle tonalité." },
  { q:"La pédale de dominante prolongée avant une récapitulation dans la forme sonate crée :", opts:["De la monotonie","L'attente maximale du retour au thème principal — la tension accumulée amplifie l'impact de la récapitulation","Une modulation vers la dominante","Un accord appogiaturé de tonique"], a:1, fb:"Dans la forme sonate, la retransition vers la récapitulation utilise souvent une longue pédale de dominante. Cette attente prolongée du retour à la tonique crée une tension structurelle forte — quand le thème revient, l'impact est décuplé." },
  { q:"Quelle est la relation entre accord appogiaturé et 6/4 de cadence ?", opts:["Ils sont identiques","I6/4 peut être analysé comme un accord appogiaturé de I sur basse de V — les deux sont des dissonances structurelles qui préparent la dominante","Aucune relation","Le 6/4 est toujours appogiaturé"], a:1, fb:"I6/4 (C/G) = accord de C avec Sol à la basse. Sol est la dominante — l'accord de C 'flotte' sur une basse de dominante. C'est analogue à un accord appogiaturé de I sur V. Les deux créent une dissonance résolue vers V7–I." },
  { q:"Les techniques de marche, note commune, minorisation et pédale peuvent :", opts:["S'exclure mutuellement","Se combiner librement — ex : une marche harmonique avec pédale, ou une minorisation avec note commune","Uniquement être utilisées séparément","S'utiliser uniquement en mineur"], a:1, fb:"Toutes ces techniques peuvent coexister et se combiner. Une progression complexe peut utiliser une marche harmonique qui s'arrête sur une note commune, puis une minorisation pour confirmer la nouvelle tonalité avec une pédale de dominante." },
  { q:"La technique la plus utilisée pour les grandes finales orchestrales est :", opts:["La marche diatonique","La pédale de tonique + accord appogiaturé + cadence parfaite — accumulation de tensions résolues sur I","La minorisation","La note commune"], a:1, fb:"Les grandes finales (Beethoven, Brahms, Mahler) accumulent les tensions : pédale de dominante puis de tonique, accords appogiaturés, 6/4, V7, résolution sur I. L'accumulation et la résolution finale créent un effet catartique puissant." },
  { q:"Dans le répertoire romantique, quelle technique de modulation est préférée pour les passages lyriques ?", opts:["La marche harmonique brutale","La modulation par note commune — sa fluidité préserve le chant mélodique","La minorisation uniquement","La pédale de dominante"], a:1, fb:"Les passages lyriques romantiques (Schubert, Schumann, Brahms) utilisent souvent la note commune pour moduler sans perturber le chant. La mélodie glisse naturellement d'une tonalité à l'autre, guidée par la note tenue." },
  { q:"La distinction entre modulation et tonicisation dans un contexte de marche harmonique est :", opts:["Impossible à faire","Déterminée par la durée du séjour dans la nouvelle tonalité — tonicisation si bref, modulation si confirmée par cadence","Déterminée par la hauteur","Toujours une modulation dans une marche harmonique"], a:1, fb:"Dans une marche harmonique, chaque étape peut être une tonicisation brève ou une modulation plus longue. Si on s'arrête et qu'une cadence parfaite confirme, c'est une modulation. Si la marche continue immédiatement, chaque étape est une tonicisation." },
];

// English translations — add when available; until then falls back to fr


const questionsEn: Question[] = [{ q:"What is a musical sequence?", opts:["A repeated chord","A melodic or harmonic pattern repeated on different scale degrees — progressively transposed","A succession of perfect cadences","A tempo change"], a:1, fb:"A sequence is a pattern repeated on different scale degrees: the pattern is shifted as if 'stepping' through the scale. Pachelbel's Canon is the classic example of a diatonic sequence." },
{ q:"The difference between a diatonic sequence and a harmonic sequence is:", opts:["The diatonic sequence is lower in pitch","The diatonic sequence stays within the scale (adjusted intervals), the harmonic sequence transposes exactly (may leave the scale)","They are identical","The harmonic sequence uses only minor chords"], a:1, fb:"Diatonic sequence: the pattern adapts to the scale's intervals — we stay in the key. Harmonic sequence: exact transposition of intervals — we leave the scale and modulate." },
{ q:"Pachelbel's Canon is an example of:", opts:["A harmonic sequence","A diatonic sequence — the pattern descends by step while staying in D major","Modulation by common note","A dominant pedal"], a:1, fb:"Pachelbel's Canon shifts the same harmonic pattern through successive scale degrees in D major — it is a diatonic sequence. The intervals adjust slightly to remain within the scale." },
{ q:"A harmonic sequence modulates because:", opts:["It uses diminished chords","It transposes the pattern with exact intervals — this forces the use of notes outside the original scale","It changes the tempo","It uses the chromatic scale"], a:1, fb:"The harmonic sequence preserves the exact intervals of the pattern. If the pattern contains a major third, each transposition will have an exact major third — which can introduce notes foreign to the scale." },
{ q:"The progression Gm–Fm–Ebm–Dbm is a sequence that is:", opts:["Diatonic in G minor","Harmonic — each chord descends by a whole tone, same type (minor), leaving the scale","Chromatic","Cadential"], a:1, fb:"Gm → Fm → Ebm → Dbm: each minor chord descends by a whole tone. The progression leaves G minor after Fm — this is a descending harmonic sequence by whole tones." },
{ q:"The diatonic sequence in Chopin's Étude op.10 no.3 stays in:", opts:["E minor","E major — the pattern moves by step while remaining within the scale","C major","A minor"], a:1, fb:"Chopin's Étude op.10 no.3 is in E major. The diatonic sequence in section A shifts the pattern by step without leaving E major. Chopin sometimes introduces slight variations of the model." },
{ q:"The harmonic sequence is a tool for modulation because:", opts:["It is very fast","Each 'step' of the sequence can be perceived as a new tonal stopping point — tension accumulates","It avoids cadences","It uses only major chords"], a:1, fb:"Each exact transposition of the harmonic sequence introduces new accidentals — each step is potentially a new key. The progression is 'journeying': we move progressively further from the starting point." },
{ q:"In a harmonic sequence, the perfect cadence at the destination serves to:", opts:["Restart the sequence","Confirm and anchor the new key — a signal that the journey is ending","Create a false lead","Return to the starting key"], a:1, fb:"After a harmonic sequence that travels through several keys, a perfect cadence in the final key confirms the arrival. Without it, we would remain in ambiguity." },
{ q:"The descending harmonic sequence by whole tones Gm–Fm–Ebm–Dbm is found in:", opts:["The chaconne bass line only","Many Romantic and jazz pieces — e.g., Misty, numerous ballads","The blues only","Baroque fugues only"], a:1, fb:"The harmonic descent by whole tones (cycle of descending seconds) is ubiquitous in jazz and Romantic pop music. It creates a sensation of progressive harmonic 'sliding.'" },
{ q:"Bach's Chaconne uses an ostinato bass that is:", opts:["A harmonic sequence","A diatonic sequence — the bass descends by step while staying in D minor","A pivot chord","A dominant pedal"], a:1, fb:"The bass of Bach's Chaconne descends by conjunct steps in D minor — D–C–Bb–A. It is a diatonic sequence in the bass (ostinato), not a harmonic sequence that would modulate." },
{ q:"Schoenberg distinguishes between a tonal sequence and a melodic sequence because:", opts:["They are different names for the same thing","The tonal sequence adapts intervals to the scale, while the melodic sequence may also slightly modify the melodic shape itself","There is no distinction","The melodic sequence is lower in pitch"], a:1, fb:"Schoenberg notes that in a tonal (diatonic) sequence, the intervals adjust, but the melodic shape may also vary slightly to fit the scale. These two concepts distinguish the harmonic and melodic levels of adaptation." },
{ q:"The progression C–G–Am–Em–F–C–Dm–G is a sequence that is:", opts:["Harmonic — it leaves C major","Diatonic — all chords belong to C major","Chromatic","Direct"], a:1, fb:"C G Am Em F C Dm G: all these chords are diatonic to C major. The progression is a diatonic sequence — the I–V pattern is transposed onto VI–III then IV–I, remaining in C." },
{ q:"An ascending harmonic sequence by semitones creates:", opts:["A soothing feeling","Intense chromatic tension — each step rises by a semitone","A blues progression","A pedal effect"], a:1, fb:"The chromatic rise by semitones (e.g., Cm–C#m–Dm–D#m) creates progressively intense chromatic tension. Used by Ravel, Chopin, and many composers for dramatic effects." },
{ q:"The harmonic sequence by the cycle of descending fifths is:", opts:["A diatonic sequence only","The same as the diatonic cycle of fifths — but in an exact, modulating version","Impossible in practice","Exclusively Baroque"], a:1, fb:"The harmonic cycle of fifths transposes the pattern by an exact fifth at each step. If we stay diatonic, it is the cycle from lesson 3. If we preserve the exact intervals, we modulate — harmonic sequence." },
{ q:"The sonic difference between a diatonic sequence and a harmonic sequence is:", opts:["None","The diatonic sequence sounds 'inside' the key; the harmonic sequence creates a sensation of tonal drift","The harmonic sequence is lower in pitch","The diatonic sequence is faster"], a:1, fb:"The diatonic sequence stays in the tonal 'homeland' — the ear recognizes the scale. The harmonic sequence 'drifts' — exact intervals introduce foreign notes, giving a sensation of progressive journeying." },
{ q:"In Étude op.10 no.3, Chopin alternates diatonic sequences with:", opts:["Chromatic sequences","Harmonic sequences at certain points — proof that both procedures coexist","Bass pedal","A Neapolitan chord"], a:1, fb:"In Étude op.10 no.3, Chopin primarily uses a diatonic sequence but introduces exact transpositions (harmonic sequence) at certain points to create slight tonal drifts." },
{ q:"To use a harmonic sequence as a modulation tool, one:", opts:["Repeats the sequence indefinitely","Stops the sequence on the new key and confirms it with a perfect cadence","Ignores the accidentals created","Always returns to the starting key"], a:1, fb:"The harmonic sequence carries us to a new key at each step. When we arrive at the desired destination, we stop the sequence and confirm the new key with a perfect cadence." },
{ q:"The pattern I–V–VI–III–IV–I–II–V in C (Pachelbel's Canon) is a sequence that is:", opts:["Harmonic — it modulates to G","Diatonic — it stays in C while shifting the I–V pattern onto different degrees","Direct — it jumps between keys","Mixed"], a:1, fb:"I–V: C–G. VI–III: Am–Em. IV–I: F–C. II–V: Dm–G. Everything stays in C major. The sequence degrees (I, VI, IV, II) are the starting point of the pattern, which adapts to the scale each time." },
{ q:"The harmonic sequence by whole tones (Gm–Fm–Ebm) is descending. If made ascending:", opts:["That is not possible","We get Gm–Am–Bm — an ascending sequence by whole tones (or by semitones depending on the chosen interval)","It becomes diatonic","It becomes a pedal"], a:1, fb:"A harmonic sequence can go in either direction. Gm–Am–Bm = ascending sequence by whole tones. Cm–Db–Dm = ascending sequence by semitones. The direction creates different expressive effects (rising tension vs. descent)." },
{ q:"The 'chromatic' sequence (by semitones) is a form of:", opts:["Diatonic sequence","Harmonic sequence — exact semitones force us to leave the scale at each step","Tonal sequence only","Plagal sequence"], a:1, fb:"A sequence by semitones transposes the pattern by a semitone each time — same exact intervals. It is a chromatic harmonic sequence. Each step introduces new accidentals." },
{ q:"Modulation by common note uses:", opts:["A chord common to both keys","A single identical note (pivot note) that serves as a link between the departure chord and the arrival chord","Two common chords","The artificial leading tone"], a:1, fb:"Modulation by common note does not use an entire chord as a pivot, but a single note that belongs to both harmonic contexts. This note changes function — it 'slides' from one role to another." },
{ q:"In modulation by common note, the pivot note is generally:", opts:["In the bass — pedal effect","In the soprano — it attracts attention and guides the ear","In the tenor — the most stable voice","In the alto — intermediate voice"], a:1, fb:"The pivot note works best in the soprano because it is the most audible. The ear follows the upper line — when it remains still while the harmony changes beneath it, the slide is smooth and perceptible." },
{ q:"Modulating from G to Eb with G as the common note:", opts:["G becomes the third of Eb major (G is the third of Eb = Eb–G–Bb)","G becomes the root of Eb","G becomes the leading tone of Eb","G does not belong to Eb"], a:0, fb:"G is the third of Eb major (Eb–G–Bb). In G major, G is the tonic. G as common note: tonic of G → third of Eb. The same pitch changes harmonic role — smooth modulation." },
{ q:"The most common notes for a modulation by common note are:", opts:["The root and the fifth","The third, seventh, ninth, and thirteenth","The leading tone only","The notes of the dominant chord"], a:1, fb:"Extension notes (third, seventh, ninth, thirteenth) are most often used as common notes because they belong to many chords in different keys." },
{ q:"If the common note is in the bass rather than in the soprano, the effect is:", opts:["Identical","More static — it acts as a pedal rather than as a melodic guiding note","More dramatic","Faster"], a:1, fb:"A common note in the bass creates a pedal effect — the harmony changes above a stationary bass. In the soprano it guides the ear melodically. Both effects are valid but different." },
{ q:"Modulation by common note is used by:", opts:["Bach only","Chopin, Liszt, Debussy, and modern jazz — particularly for modulations to remote keys","Mozart only","The Baroque only"], a:1, fb:"This technique is characteristic of Romanticism (Chopin, Liszt, Schubert) and Impressionism (Debussy). In jazz, a pivot note can be the third or seventh of the new chord — reharmonization." },
{ q:"Modulation by common note can reach:", opts:["Only neighboring keys","Remote keys smoothly — the common note creates an imperceptible link despite the distance","Only the relative minor","The same key (tautology)"], a:1, fb:"Modulation by common note is particularly useful for remote keys (mediants, keys at a third's distance) — a diatonic pivot chord would be hard to find, but a single note suffices." },
{ q:"Modulation to the mediant (key at a third's distance) often uses:", opts:["A diatonic pivot chord","The common note — the third of the departure chord becomes the root or third of the new key","A direct cadence only","The cycle of fifths"], a:1, fb:"Mediant modulations (by thirds) are ideal for the common note: the third of the departure chord often becomes a structural note of the new key. E.g., G = third of C → tonic of G (classic modulation) or third of Eb." },
{ q:"The progression G major → Eb major with G in the soprano illustrates:", opts:["A blunt direct modulation","A modulation by common note: G = tonic of G → third of Eb","A tonicization of Eb","A tonic pedal"], a:1, fb:"G is the tonic of G. In Eb major (Eb–G–Bb), G is the third. By maintaining G in the soprano while the harmony slides from G to Eb, we hear the same note in two different contexts — very smooth modulation." },
{ q:"In jazz, reharmonization by common note consists of:", opts:["Playing a different chord with the same bass","Keeping an important note (third or seventh) of the original chord in the replacement chord","Transposing all chords","Removing the melody"], a:1, fb:"In jazz reharmonization, a chord is replaced while retaining one of its structural notes (often the third or seventh) in the new chord. Melodic continuity masks the harmonic change." },
{ q:"The common note works particularly well when it is:", opts:["On a weak beat","Held or repeated — its duration gives it time to change function without a break","Very short","On the weakest beat of the measure"], a:1, fb:"A common note must be heard long enough for the ear to identify it in the first context, then reinterpret it in the second. A note that is too short would not allow this dual perception." },
{ q:"Modulation by common note differs from modulation by pivot chord because:", opts:["The pivot chord is more dramatic","The common note uses a single pitch as a link (not a whole chord) — more subtle, more useful for remote keys","They are identical","The pivot chord is more recent"], a:1, fb:"The pivot chord shares an entire chord between two keys — works well for closely related keys. The common note shares a single pitch — more flexible, allows reaching very remote keys smoothly." },
{ q:"If E is the common note between C major (third) and A minor (tonic), one can modulate:", opts:["Only from C to Am","In both directions: C→Am (E = III of C = I of Am) or Am→C (E = I of Am = III of C)","Only using G7","Only in harmonic minor"], a:1, fb:"A common note works in both directions. E = III of C and I of Am. We can therefore modulate C→Am (E stays, role changes) or Am→C (E stays, role changes in the other direction). Same mechanism, opposite directions." },
{ q:"Modulation by common note creates a feeling of:", opts:["Dramatic rupture","Imperceptible sliding — the ear is guided by the held note while the harmony changes discreetly","Rhythmic acceleration","Intense chromatic instability"], a:1, fb:"This is the great strength of this technique: the harmonic change is almost imperceptible thanks to the sustained note. The ear follows the guiding thread of the common note and 'slides' naturally toward the new key." },
{ q:"In a modulation by common note, what 'moves' and what 'stays'?", opts:["Everything moves","The harmony moves (the chords change), the common note stays — the guiding thread","Nothing moves — it is a pedal","The melody stays, everything else moves"], a:1, fb:"The common note is the stability within change: it remains still (or is repeated) while all the harmony around it transforms. It is this contrast between stability and movement that creates the fluidity." },
{ q:"The common note is sometimes called a 'pivot note' by analogy with:", opts:["The pivot chord","The harmonic pedal","Both — in both cases an element 'pivots' between two functional contexts","The Neapolitan chord"], a:2, fb:"By analogy with the pivot chord (an entire chord pivoting between two keys), the common note is a 'pivot note' — a single pitch that pivots between two contexts. The logic is identical, the scale is different." },
{ q:"Minorization of a chord consists of:", opts:["Playing it in minor without altering the tonal context","Lowering the major third by a semitone to make the chord minor — often transforming it into a bridge toward a new key","Transposing it by a semitone","Playing it in inversion"], a:1, fb:"Minorization lowers the third of a major chord to make it minor. E.g., C (C–E–G) → Cm (C–Eb–G). This new minor chord can be reinterpreted in another key." },
{ q:"The expressive effect of minorization is:", opts:["Joy","A sudden melancholy — lowering the third creates an emotional shift toward darkness","Rhythmic tension","Tonal clarity"], a:1, fb:"Minorization creates an immediate emotional shift — the minor third brings a melancholic color that contrasts with the preceding major chord. It is one of the most expressive effects in tonal harmony." },
{ q:"In the progression C → Cm → F7 → Bb, Cm is:", opts:["A borrowing from C minor","The minorization of C, reinterpreted as II of Bb major — it initiates the modulation toward Bb","A tonicization of Bb","A Neapolitan chord"], a:1, fb:"C (I of C) → Cm (minorization, minorized I) → Cm reinterpreted as IIm of Bb → F7 (V of Bb) → Bb (I of Bb). The minorization of C transforms it into IIm of Bb — modulation from C to Bb." },
{ q:"The modulation by minorization from C to Bb works because:", opts:["C and Bb have the same key signature","Cm (C–Eb–G) is the second degree of Bb major (Bb–C–D–Eb–F–G–A). Cm reinterprets naturally in Bb.","Cm is the dominant of Bb","C and Bb are a fifth apart"], a:1, fb:"Cm = C–Eb–G. In Bb major, the second degree = Cm. The minorization of C (C→Cm) transforms it into IIm of Bb, which naturally prepares F7 (V of Bb) then Bb. Elegant and economical." },
{ q:"Majorization is the inverse operation of minorization:", opts:["False — minorization is irreversible","True — the minor third is raised by a semitone to make a minor chord major","False — the two are identical","True — but majorization is far more common"], a:1, fb:"Majorization (minor → major) is the inverse of minorization. It is less common but exists — e.g., Am → A (major) can initiate a tonicization or modulation. Minorization remains expressively more frequent." },
{ q:"The progression I → Im is an example of:", opts:["Direct modulation","Minorization of the tonic — very expressive, often used in codas","Borrowing from the parallel minor only","A dominant pedal"], a:1, fb:"I → Im is a minorization of the tonic — C → Cm. It is one of the most expressive transitions: the tonic itself darkens. Widely used in Romantic codas and melancholic conclusions." },
{ q:"IV → IVm (e.g., F → Fm in C major) is:", opts:["A Neapolitan chord","A classic Romantic borrowing — the minorization of the subdominant","A tonicization of Fm","A modulation to C minor"], a:1, fb:"F → Fm = minorization of the fourth degree. It is one of the most common borrowings in Romanticism. The dark color of Fm contrasts with F and enriches the progression. It may initiate a modulation or remain a simple borrowing." },
{ q:"Minorization is sometimes called a 'modal shift' because:", opts:["It changes the tempo","It transforms the mode of the chord (major → minor) — analogous to changing the mode of a scale","It uses two key signatures","It changes the meter"], a:1, fb:"Minorization is a local mode change: the chord shifts from major to minor mode. It is analogous to moving from a major scale to its parallel minor — but at the scale of a single chord." },
{ q:"V → Vm is rarer than I → Im because:", opts:["V minor does not exist","V minor loses the leading tone — Gm does not have B natural (leading tone of C), weakening the cadential tension","V minor is outside the key","V minor is too low in pitch"], a:1, fb:"Gm (G–Bb–D) does not have B natural — the leading tone of C is lost. Gm therefore has less cadential tension than G or G7. V → Vm is a weakening of the dominant — rare, but used for specific effects (e.g., modal cadence)." },
{ q:"The progression Am–G–F–E7–Am in A minor illustrates:", opts:["A minorization","A majorization of the fifth degree — Em becomes E7 (major with seventh) to create the leading tone G#","A harmonic sequence","A dominant pedal"], a:1, fb:"E7 (E–G#–B–D) is the majorization-functionalization of the fifth degree of A minor. In natural minor, the fifth degree would be Em (minor, without G#). The harmonic minor 'majorizes' the dominant to create the leading tone." },
{ q:"Minorization can create a modulation toward:", opts:["The relative minor only","The key in which the minorized chord becomes a natural functional degree — often the key a fourth above","The same key","Only remote keys"], a:1, fb:"Minorization of C (C→Cm) prepares Bb (Cm = IIm of Bb). In general, the minorized chord becomes the IIm of the new key — a fourth above. E.g., D→Dm prepares C (Dm = IIm of C). Always a fourth above." },
{ q:"What notation indicates a minorization in a chord chart?", opts:["The chord followed by '7'","The chord followed by 'm' — e.g., C becomes Cm","The chord followed by 'aug'","The chord followed by 'dim'"], a:1, fb:"The minorization of C is written Cm in American notation. The 'm' indicates that the third is lowered by a semitone. C = C–E–G, Cm = C–Eb–G." },
{ q:"In the progression C–Cm–Bb–F, Cm initiates a modulation toward:", opts:["F major","Bb major — Cm = IIm of Bb, prepares F7 (V of Bb) then Bb","G minor","C minor definitively"], a:1, fb:"Cm = IIm of Bb major. The progression Cm–F7 would be SD–D in Bb, but here we have Cm–Bb directly. The modulation toward Bb is initiated by the minorization of C." },
{ q:"The minorization of the fourth degree (F → Fm in C) is often followed by:", opts:["G7 directly","C (tonic) for a minor plagal cadence","D7","Am"], a:1, fb:"The progression C–Fm–C is a minor plagal cadence — Fm replaces F as the subdominant. It is a very expressive borrowing. One can also proceed to G7: C–Fm–G7–C = borrowed SD–D–T." },
{ q:"A harmonic pedal is:", opts:["A repeated chord that does not change","A note held or repeated while the other voices change chords","A fixed dominant chord","A melodic ornament"], a:1, fb:"The harmonic pedal is a note sustained (held or repeated) in one voice while the harmonies change around it. It may belong to the passing chords or be foreign to them — in the latter case creating dissonances." },
{ q:"The tonic pedal creates:", opts:["Maximum tension","Stability — it anchors the tonal center by maintaining the tonic root","A modulation","A suspension"], a:1, fb:"The tonic pedal sustains the first degree (C in C major) while the harmony evolves. It anchors the tonal center — the ear never loses the thread of the tonic. Often used at the beginning or end of a movement." },
{ q:"The dominant pedal prepares:", opts:["A new key","The final cadence — the sustained dominant creates prolonged tension that amplifies the resolution onto I","A tonic pedal","A Neapolitan chord"], a:1, fb:"The dominant pedal sustains G (in C major) while the chords change above. This prolonged tension makes the final resolution onto C all the more satisfying. Widely used before large cadences." },
{ q:"The double pedal simultaneously sustains:", opts:["Any two roots","Both tonal poles — tonic and dominant (C and G in C major)","The third and the fifth","Two secondary dominants"], a:1, fb:"The double pedal simultaneously sustains I and V — C and G in C major. It anchors the two fundamental poles of the key, creating a very stable foundation for moving harmonies above." },
{ q:"The soprano pedal is characteristic of:", opts:["Baroque music only","Nineteenth-century music and Impressionism (Debussy, Ravel)","Fugue only","Modern jazz only"], a:1, fb:"The soprano pedal — a note held in the upper voice — is particularly developed in Romanticism and Impressionism. Debussy uses it abundantly to create effects of suspension and harmonic ambiguity." },
{ q:"A pedal is 'foreign' when:", opts:["It is played loudly","It does not belong to the chord passing above it — it creates a temporary dissonance","It is very low in pitch","It lasts only one measure"], a:1, fb:"A foreign pedal does not belong to the current chord — it creates a dissonance. This dissonance is resolved when a chord containing the pedal note arrives. The effect of tension is expressive." },
{ q:"The progression C–Am–F–G with C held in the bass is a pedal of:", opts:["Dominant","Tonic — C is the first degree of C major, it stays in the bass throughout the progression","Double pedal","Soprano pedal"], a:1, fb:"C is the tonic of C major. Held in the bass during Am, F, and G (not all of which contain C as their root), it creates a tonic pedal. The effect anchors C as the center while the harmony evolves." },
{ q:"The progression Dm–G7–C with G held in the bass is a pedal of:", opts:["Tonic","Dominant — G is the fifth degree of C major. It remains still while Dm and G7 pass","Double pedal","Soprano pedal"], a:1, fb:"G is the dominant of C. Held in the bass during Dm and G7, it creates a dominant pedal. The tension is at its maximum — G only resolves to C at the end. Widely used before large cadences." },
{ q:"The tonic pedal is often used:", opts:["In the middle of a tense development","At the beginning or end of a piece — to stabilize and anchor the tonal center","Only in minor","To modulate"], a:1, fb:"The tonic pedal is a stabilizing tool — it is natural at the beginning of a piece (to establish the key) or at the end (to confirm it definitively). In the middle, it can create an effect of rest or a point of repose." },
{ q:"What distinguishes a pedal from a repeated chord?", opts:["Nothing — they are the same thing","In a pedal, a single note is held while the other voices change freely. A repeated chord repeats all its notes together.","The pedal is always lower in pitch","The repeated chord is always fortissimo"], a:1, fb:"Pedal = one immobile note, changing harmonies around it. Repeated chord = all the notes of the chord repeat together. The pedal maintains a melodic continuity in one voice during harmonic change." },
{ q:"In musical form, the dominant pedal is often used:", opts:["At the beginning of a piece","Before the recapitulation in sonata form — it creates the expectation of a return to the tonic","In the development only","At the end of a piece only"], a:1, fb:"In sonata form, the dominant pedal often precedes the recapitulation — the sustained dominant over several measures creates intense expectation of the return of the main theme in the tonic. Very effective dramatic device." },
{ q:"A pedal can be:", opts:["In the bass only","In any voice — bass, soprano, alto, or tenor","In the soprano only","In the inner voices only"], a:1, fb:"A pedal can occupy any voice. The bass is the most common (tonic and dominant pedals). The soprano is used for effects of suspension and Impressionism. Inner voices are rarer but possible." },
{ q:"A double pedal (C + G) creates an effect of:", opts:["Modulation toward G","Tonal ambiguity — both poles are maintained, allowing free harmonies","A prolonged perfect cadence","A diminished chord"], a:1, fb:"The double pedal C–G simultaneously maintains the tonic and dominant — the two fundamentals of the key. Above it, the harmony can venture freely without losing the tonal thread. Simultaneous stability and ambiguity." },
{ q:"The dominant pedal creates dissonances because:", opts:["The note G does not sound well","The chords passing above (IV, II) contain notes that 'clash' with G","The voices cross","The leading tone is not resolved"], a:1, fb:"G (pedal) + F major above = G + F–A–C. G and F are a seventh apart — dissonance. G + Dm = G + D–F–A. These dissonances create the tension that is resolved onto C when G is part of the chord." },
{ q:"Chopin often uses a pedal of:", opts:["Soprano only","Dominant in his nocturnes — the bass holds G while the harmony evolves richly","Tonic only","Double pedal only"], a:1, fb:"Chopin's Nocturnes frequently use the dominant pedal in the left-hand bass (often in octaves) while the right hand plays complex and ornate harmonies. The effect is very Romantic." },
{ q:"The soprano pedal is particularly used in:", opts:["Baroque fugues","Impressionism (Debussy, Ravel) — it creates appoggiatura chords and suspended harmonies","The blues only","Classical sonata form"], a:1, fb:"Debussy and Ravel make abundant use of the soprano pedal — often the dominant or the mediant — to create the floating and ambiguous harmonies characteristic of their Impressionist style." },
{ q:"The progression G7–C where G is held in the bass during C is:", opts:["A dominant pedal","A tonic pedal — G is the fifth of C, which remains after G7 has resolved","A double pedal","A foreign pedal"], a:1, fb:"When G7 resolves to C, G (bass) may remain — G is the fifth of C. This held G is now a pedal on the fifth (or a sustained dominant). It creates no dissonance within C but gives a I6/4 color." },
{ q:"The dominant pedal in a Bach fugue is often:", opts:["A single measure","A long hold of several measures in the bass before the stretto or the final cadence","A quick ornament","A repeated note in the soprano"], a:1, fb:"In Bach's fugues, the dominant pedal (organ pedal) is often a G held for several measures in the bass while the upper voices move energetically. It is a technique characteristic of fugal writing." },
{ q:"The term 'organ pedal' comes from:", opts:["The tempo pedal","The organ's pedal keyboard — the performer can hold a note with the foot while both hands play other harmonies","Expression pedals","Piano pedals"], a:1, fb:"The organ has a bass keyboard played with the feet (the pedalboard). The organist can hold a note with the foot while both hands play freely. This technique inspired the concept of the harmonic pedal throughout composition." },
{ q:"Which pedal is the rarest in classical writing?", opts:["Tonic pedal","Dominant pedal","Inner-voice pedal (held intermediate voice)","Double pedal"], a:2, fb:"A pedal in an inner voice (alto or tenor) is the rarest — difficult to perceive and to manage technically. Bass and soprano pedals are far more common because they occupy the extreme registers, which are more audible." },
{ q:"In a double pedal C–G, which of the two is the lower?", opts:["G","C — C3 is lower than G3","They are at the same octave","It depends on the voices"], a:1, fb:"C3 (octave 3) is lower than G3. In a classic bass double pedal, C is often placed in the bass with G a fifth above — or both in octaves (C3 and C4, G2 and G3)." },
];

const questionsEs: Question[] = [{ q:"¿Qué es una marcha musical?", opts:["Un acorde repetido","Un motivo melódico o armónico repetido en diferentes grados — transpuesto progresivamente","Una sucesión de cadencias perfectas","Un cambio de tempo"], a:1, fb:"Una marcha (o secuencia) es un motivo repetido en diferentes grados: se desplaza el motivo como si se 'marchara' por etapas. El Canon de Pachelbel es el ejemplo clásico de marcha diatónica." },
{ q:"La diferencia entre marcha diatónica y marcha armónica es:", opts:["La marcha diatónica es más grave","La marcha diatónica permanece en la escala (intervalos ajustados), la marcha armónica transpone exactamente (puede salir de la escala)","Son idénticas","La marcha armónica utiliza únicamente acordes menores"], a:1, fb:"Marcha diatónica: el motivo se adapta a los intervalos de la escala — se permanece en la tonalidad. Marcha armónica: transposición exacta de los intervalos — se sale de la escala y se modula." },
{ q:"El Canon de Pachelbel es un ejemplo de:", opts:["Marcha armónica","Marcha diatónica — el motivo desciende por grados permaneciendo en D mayor","Modulación por nota común","Pedal de dominante"], a:1, fb:"El Canon de Pachelbel desplaza el mismo motivo armónico por grados sucesivos en D mayor — es una marcha diatónica. Los intervalos se ajustan ligeramente para permanecer en la escala." },
{ q:"Una marcha armónica modula porque:", opts:["Utiliza acordes disminuidos","Transpone el motivo con intervalos exactos — eso obliga a usar notas fuera de la escala de partida","Cambia el tempo","Utiliza la escala cromática"], a:1, fb:"La marcha armónica preserva los intervalos exactos del motivo. Si el motivo contiene una tercera mayor, cada transposición tendrá una tercera mayor exacta — lo que puede introducir notas ajenas a la escala." },
{ q:"La progresión Gm–Fm–Ebm–Dbm es una marcha:", opts:["Diatónica en G menor","Armónica — cada acorde desciende un tono, mismo tipo (menor), saliendo de la escala","Cromática","Cadencial"], a:1, fb:"Gm → Fm → Ebm → Dbm: cada acorde menor desciende un tono entero. La progresión sale de G menor después de Fm — es una marcha armónica descendente por tonos." },
{ q:"La marcha diatónica del Estudio op.10 n°3 de Chopin permanece en:", opts:["E menor","E mayor — el motivo se desplaza por grados permaneciendo en la escala","C mayor","A menor"], a:1, fb:"El Estudio op.10 n°3 de Chopin está en E mayor. La marcha diatónica de la sección A desplaza el motivo por grados sin salir de E mayor. Chopin introduce a veces ligeras variantes del modelo." },
{ q:"La marcha armónica es una herramienta de modulación porque:", opts:["Es muy rápida","Cada 'etapa' de la marcha puede percibirse como una nueva escala tonal — la tensión se acumula","Evita las cadencias","Utiliza únicamente acordes mayores"], a:1, fb:"Cada transposición exacta de la marcha armónica introduce nuevas alteraciones — cada etapa es potencialmente una nueva tonalidad. La progresión es 'viajera': uno se aleja progresivamente del punto de partida." },
{ q:"En una marcha armónica, la cadencia perfecta a la llegada sirve para:", opts:["Reiniciar la marcha","Confirmar y anclar la nueva tonalidad — señal de que el viaje termina","Crear una pista falsa","Volver a la tonalidad de partida"], a:1, fb:"Después de una marcha armónica que viaja a través de varias tonalidades, una cadencia perfecta en la tonalidad final confirma la llegada. Sin ella, se permanecería en la ambigüedad." },
{ q:"La marcha armónica descendente por tonos Gm–Fm–Ebm–Dbm se encuentra en:", opts:["El bajo de chacona únicamente","Muchas piezas románticas y de jazz — ej: Misty, numerosas baladas","El blues únicamente","Las fugas barrocas únicamente"], a:1, fb:"El descenso armónico por tonos (ciclo de segundas descendentes) es omnipresente en el jazz y en la música pop romántica. Crea una sensación de 'deslizamiento' armónico progresivo." },
{ q:"La Chacona de Bach utiliza un bajo ostinato que es:", opts:["Una marcha armónica","Una marcha diatónica — el bajo desciende por grados permaneciendo en D menor","Un acorde pivote","Un pedal de dominante"], a:1, fb:"El bajo de la Chacona de Bach desciende por grados conjuntos en D menor — D–C–Bb–A. Es una marcha diatónica en el bajo (ostinato), no una marcha armónica que modularía." },
{ q:"Schoenberg distingue marcha tonal y marcha melódica porque:", opts:["Son nombres distintos para la misma cosa","La marcha tonal adapta los intervalos a la escala, la marcha melódica puede modificar ligeramente el propio diseño melódico","No hay distinción","La marcha melódica es más grave"], a:1, fb:"Schoenberg señala que en una marcha tonal (diatónica), los intervalos se ajustan pero también el diseño melódico puede variar ligeramente para adaptarse a la escala. Estas dos nociones distinguen el nivel armónico y melódico de la adaptación." },
{ q:"La progresión C–G–Am–Em–F–C–Dm–G es una marcha:", opts:["Armónica — sale de C mayor","Diatónica — todos los acordes pertenecen a C mayor","Cromática","Directa"], a:1, fb:"C G Am Em F C Dm G: todos estos acordes son diatónicos a C mayor. La progresión es una marcha diatónica — el motivo I–V se transpone sobre VI–III luego IV–I, permaneciendo en C." },
{ q:"Una marcha armónica ascendente por semitonos crea:", opts:["Una sensación apaciguadora","Una tensión cromática intensa — cada etapa sube un semitono","Una progresión azul","Un efecto de pedal"], a:1, fb:"El ascenso cromático por semitonos (ej: Cm–C#m–Dm–D#m) crea una tensión cromática progresiva muy intensa. Utilizada por Ravel, Chopin y numerosos compositores para efectos dramáticos." },
{ q:"La marcha armónica por ciclo de quintas descendentes es:", opts:["Una marcha diatónica únicamente","Lo mismo que el ciclo de quintas diatónicas — pero en versión exacta, modulante","Imposible en la práctica","Exclusivamente barroca"], a:1, fb:"El ciclo de quintas armónicas transpone exactamente el motivo de quinta en cada etapa. Si se permanece diatónico, es el ciclo visto en el tema 3. Si se preservan los intervalos exactos, se modula — marcha armónica." },
{ q:"La diferencia sonora entre marcha diatónica y marcha armónica es:", opts:["Ninguna","La marcha diatónica suena 'dentro' de la tonalidad, la marcha armónica crea una sensación de deriva tonal","La marcha armónica es más grave","La marcha diatónica es más rápida"], a:1, fb:"La marcha diatónica permanece en el 'país' tonal — el oído reconoce la escala. La marcha armónica 'deriva' — los intervalos exactos crean notas ajenas, dando una sensación de viaje progresivo." },
{ q:"En el Estudio op.10 n°3, Chopin alterna marcha diatónica y:", opts:["Marcha cromática","Marcha armónica en ciertos lugares — prueba de que ambos procedimientos coexisten","Pedal de bajo","Acorde napolitano"], a:1, fb:"En el Estudio op.10 n°3, Chopin utiliza principalmente una marcha diatónica pero introduce en algunos lugares transposiciones exactas (marcha armónica) para crear ligeras derivas tonales." },
{ q:"Para utilizar una marcha armónica como herramienta de modulación, se:", opts:["Repite la marcha indefinidamente","Detiene la marcha en la nueva tonalidad y la confirma con una cadencia perfecta","Ignoran las alteraciones creadas","Vuelve siempre a la tonalidad de partida"], a:1, fb:"La marcha armónica transporta hacia una nueva tonalidad en cada etapa. Cuando se llega al destino deseado, se detiene la marcha y se confirma la nueva tonalidad con una cadencia perfecta." },
{ q:"El patrón I–V–VI–III–IV–I–II–V en C (Canon de Pachelbel) es una marcha:", opts:["Armónica — modula a G","Diatónica — permanece en C desplazando el motivo I–V sobre diferentes grados","Directa — salta entre tonalidades","Mixta"], a:1, fb:"I–V: C–G. VI–III: Am–Em. IV–I: F–C. II–V: Dm–G. Todo permanece en C mayor. Los grados de la marcha (I, VI, IV, II) son el punto de partida del motivo, que se adapta cada vez a la escala." },
{ q:"La marcha armónica por tonos (Gm–Fm–Ebm) es descendente. Si se la hace ascendente:", opts:["No es posible","Se obtiene Gm–Am–Bm — una marcha ascendente por tonos (o por semitonos según el intervalo elegido)","Se vuelve diatónica","Se convierte en un pedal"], a:1, fb:"Una marcha armónica puede ir en ambas direcciones. Gm–Am–Bm = marcha ascendente por tonos. Cm–Db–Dm = marcha ascendente por semitonos. La dirección crea efectos expresivos diferentes (tensión ascendente vs descenso)." },
{ q:"La marcha 'cromática' (por semitonos) es una forma de marcha:", opts:["Diatónica","Armónica — los semitonos exactos obligan a salir de la escala en cada etapa","Tonal únicamente","Plagal"], a:1, fb:"Una marcha por semitonos transpone el motivo un semitono en cada vez — mismos intervalos exactos. Es una marcha armónica cromática. Cada etapa introduce nuevas alteraciones." },
{ q:"La modulación por nota común utiliza:", opts:["Un acorde común a las dos tonalidades","Una sola nota idéntica (nota pivote) que sirve de enlace entre el acorde de partida y el acorde de llegada","Dos acordes comunes","La sensible artificial"], a:1, fb:"La modulación por nota común no utiliza un acorde entero como pivote, sino una sola nota que pertenece a los dos contextos armónicos. Esta nota cambia de función — 'se desliza' de un papel a otro." },
{ q:"En la modulación por nota común, la nota pivote está generalmente:", opts:["En el bajo — efecto de pedal","En el soprano — atrae la atención y guía el oído","En el tenor — voz más estable","En el alto — voz intermedia"], a:1, fb:"La nota pivote funciona mejor en el soprano porque es la más audible. El oído sigue la línea superior — cuando permanece inmóvil mientras la armonía cambia por debajo, el deslizamiento es fluido y perceptible." },
{ q:"Al modular de G hacia Eb con Sol como nota común:", opts:["Sol se convierte en la tercera de Eb mayor (Sol es la tercera de Eb = Mi♭–Sol–Si♭)","Sol se convierte en la fundamental de Eb","Sol se convierte en la sensible de Eb","Sol no pertenece a Eb"], a:0, fb:"Sol es la tercera de Eb mayor (Mi♭–Sol–Si♭). En G mayor, Sol es la tónica. Sol como nota común: tónica de G → tercera de Eb. La misma altura cambia de papel armónico — modulación fluida." },
{ q:"Las notas más frecuentes para una modulación por nota común son:", opts:["La fundamental y la quinta","La tercera, la séptima, la novena y la decimotercera","La sensible únicamente","Las notas del acorde de dominante"], a:1, fb:"Las notas de extensión (tercera, séptima, novena, decimotercera) son las más utilizadas como notas comunes porque pertenecen a muchos acordes en distintas tonalidades." },
{ q:"Si la nota común está en el bajo en lugar del soprano, el efecto es:", opts:["Idéntico","Más estático — actúa como un pedal más que como una nota melódica conductora","Más dramático","Más rápido"], a:1, fb:"Una nota común en el bajo crea un efecto de pedal — la armonía cambia sobre un bajo inmóvil. En el soprano, guía el oído melódicamente. Ambos efectos son válidos pero distintos." },
{ q:"La modulación por nota común es utilizada por:", opts:["Bach únicamente","Chopin, Liszt, Debussy y el jazz moderno — particularmente para las modulaciones hacia tonos lejanos","Mozart únicamente","El barroco únicamente"], a:1, fb:"Esta técnica es característica del romanticismo (Chopin, Liszt, Schubert) y del impresionismo (Debussy). En jazz, una nota pivote puede ser la tercera o la séptima del nuevo acorde — rearmonización." },
{ q:"La modulación por nota común permite alcanzar:", opts:["Únicamente los tonos vecinos","Tonalidades lejanas de manera fluida — la nota común crea un enlace imperceptible a pesar de la distancia","Únicamente el relativo menor","La misma tonalidad (tautología)"], a:1, fb:"La modulación por nota común es particularmente útil para las tonalidades lejanas (mediante, tonos a distancia de tercera) — el acorde pivote diatónico sería difícil de encontrar, pero una sola nota es suficiente." },
{ q:"La modulación hacia la mediante (tonalidad a una tercera) usa a menudo:", opts:["Un acorde pivote diatónico","La nota común — la tercera del acorde de partida se convierte en la fundamental o la tercera de la nueva tonalidad","Una cadencia directa únicamente","El ciclo de quintas"], a:1, fb:"Las modulaciones por terceras (mediante) son ideales para la nota común: la tercera del acorde de partida se convierte frecuentemente en una nota estructural de la nueva tonalidad. Ej: Sol = tercera de C → tónica de G (modulación clásica) o tercera de Eb." },
{ q:"La progresión G mayor → Mi♭ mayor con Sol en el soprano ilustra:", opts:["Una modulación directa brusca","Una modulación por nota común: Sol = tónica de G → tercera de Eb","Una tonicización de Eb","Un pedal de tónica"], a:1, fb:"Sol es la tónica de G. En Eb mayor (Mi♭–Sol–Si♭), Sol es la tercera. Manteniendo Sol en el soprano mientras la armonía pasa de G a Eb, se escucha la misma nota en dos contextos distintos — modulación muy fluida." },
{ q:"En jazz, la rearmonización por nota común consiste en:", opts:["Tocar un acorde diferente con el mismo bajo","Conservar una nota importante (tercera o séptima) del acorde original en el nuevo acorde de sustitución","Transponer todos los acordes","Suprimir la melodía"], a:1, fb:"En la rearmonización jazz, se reemplaza un acorde conservando una de sus notas estructurales (frecuentemente la tercera o la séptima) en el nuevo acorde. La continuidad melódica enmascara el cambio armónico." },
{ q:"La nota común funciona particularmente bien cuando está:", opts:["En un tiempo débil","Sostenida o repetida — su duración le da tiempo de cambiar de función sin ruptura","Muy corta","En el tiempo más débil del compás"], a:1, fb:"Una nota común debe escucharse suficiente tiempo para que el oído la identifique en el primer contexto y luego la reinterprete en el segundo. Una nota demasiado corta no permitiría esta doble percepción." },
{ q:"La modulación por nota común difiere de la modulación por acorde pivote porque:", opts:["El acorde pivote es más dramático","La nota común utiliza un solo sonido como enlace (no un acorde entero) — más sutil, más usada para los tonos lejanos","Son idénticas","El acorde pivote es más reciente"], a:1, fb:"El acorde pivote comparte un acorde entero entre dos tonalidades — funciona bien para los tonos cercanos. La nota común comparte una sola altura — más flexible, permite alcanzar tonos muy lejanos de manera fluida." },
{ q:"Si Mi es la nota común entre C mayor (tercera) y A menor (tónica), se puede modular:", opts:["Únicamente de C hacia Am","En ambas direcciones: C→Am (Mi = III de C = I de Am) o Am→C (Mi = I de Am = III de C)","Únicamente usando G7","Únicamente en menor armónico"], a:1, fb:"Una nota común funciona en ambas direcciones. Mi = III de C y I de Am. Se puede por tanto modular C→Am (Mi permanece, papel cambia) o Am→C (Mi permanece, papel cambia en sentido contrario). Mismo mecanismo, direcciones opuestas." },
{ q:"La modulación por nota común crea una sensación de:", opts:["Ruptura dramática","Deslizamiento imperceptible — el oído es guiado por la nota sostenida mientras la armonía cambia discretamente","Aceleración rítmica","Inestabilidad cromática intensa"], a:1, fb:"Esta es la gran fuerza de esta técnica: el cambio armónico es casi imperceptible gracias a la nota mantenida. El oído sigue el hilo conductor de la nota común y 'se desliza' naturalmente hacia la nueva tonalidad." },
{ q:"En una modulación por nota común, ¿qué 'se mueve' y qué 'permanece'?", opts:["Todo se mueve","La armonía se mueve (los acordes cambian), la nota común permanece — el hilo conductor","Nada se mueve — es un pedal","La melodía permanece, todo lo demás se mueve"], a:1, fb:"La nota común es la estabilidad en el cambio: permanece inmóvil (o repetida) mientras toda la armonía a su alrededor se transforma. Es este contraste entre estabilidad y movimiento el que crea la fluidez." },
{ q:"La nota común se llama a veces 'nota pivote' por analogía con:", opts:["El acorde pivote","El pedal armónico","Ambos — en los dos casos, un elemento 'pivota' entre dos contextos funcionales","El acorde napolitano"], a:2, fb:"Por analogía con el acorde pivote (un acorde entero que pivota entre dos tonalidades), la nota común es una 'nota pivote' — un solo sonido que pivota entre dos contextos. La lógica es idéntica, la escala es diferente." },
{ q:"La minorización de un acorde consiste en:", opts:["Tocarlo en menor sin alterar el contexto tonal","Bajar la tercera mayor un semitono para hacer el acorde menor — transformándolo frecuentemente en puente hacia una nueva tonalidad","Transponerlo un semitono","Tocarlo en inversión"], a:1, fb:"La minorización baja la tercera de un acorde mayor para hacerlo menor. Ej: C (Do–Mi–Sol) → Cm (Do–Mi♭–Sol). Este nuevo acorde menor puede reinterpretarse en otra tonalidad." },
{ q:"El efecto expresivo de la minorización es:", opts:["Alegría","Una melancolía súbita — el descenso de la tercera crea un deslizamiento emocional hacia la sombra","Tensión rítmica","Claridad tonal"], a:1, fb:"La minorización crea un deslizamiento emocional inmediato — la tercera menor aporta un color melancólico que contrasta con el acorde mayor precedente. Es uno de los efectos más expresivos de la armonía tonal." },
{ q:"En la progresión C → Cm → F7 → Bb, Cm es:", opts:["Un préstamo a C menor","La minorización de C, reinterpretada como II de Bb mayor — inicia la modulación hacia Bb","Una tonicización de Bb","Un acorde napolitano"], a:1, fb:"C (I de C) → Cm (minorización, I minorizado) → Cm reinterpretado como IIm de Bb → F7 (V de Bb) → Bb (I de Bb). La minorización de C lo transforma en IIm de Bb — modulación de C hacia Bb." },
{ q:"La modulación por minorización de C hacia Bb funciona porque:", opts:["C y Bb tienen la misma armadura","Cm (Do–Mi♭–Sol) es el IIº grado de Bb mayor (Si♭–Do–Ré–Mi♭–Fa–Sol–La). Cm se reinterpreta naturalmente en Bb.","Cm es la dominante de Bb","C y Bb están a una quinta uno del otro"], a:1, fb:"Cm = Do–Mi♭–Sol. En Bb mayor, el IIº grado = Cm. La minorización de C (C→Cm) lo transforma en IIm de Bb, que prepara naturalmente F7 (V de Bb) y luego Bb. Elegante y económico." },
{ q:"La mayorización es la operación inversa de la minorización:", opts:["Falso — la minorización es irreversible","Verdadero — se eleva la tercera menor un semitono para hacer un acorde menor mayor","Falso — las dos son idénticas","Verdadero — pero la mayorización es mucho más frecuente"], a:1, fb:"La mayorización (menor → mayor) es el inverso de la minorización. Es menos frecuente pero existe — ej: Am → A (mayor) puede iniciar una tonicización o una modulación. La minorización sigue siendo más frecuente expresamente." },
{ q:"La progresión I → Im es un ejemplo de:", opts:["Modulación directa","Minorización de la tónica — muy expresiva, frecuente en las codas","Préstamo al homónimo únicamente","Pedal de dominante"], a:1, fb:"I → Im es una minorización de la tónica — C → Cm. Es una de las transiciones más expresivas: la propia tónica se oscurece. Muy utilizada en las codas románticas y en las conclusiones melancólicas." },
{ q:"IV → IVm (ej: F → Fm en C mayor) es:", opts:["Un acorde napolitano","Un préstamo clásico del romanticismo — la minorización de la subdominante","Una tonicización de Fm","Una modulación a C menor"], a:1, fb:"F → Fm = minorización del IVº grado. Es uno de los préstamos más frecuentes del romanticismo. El color oscuro del Fm contrasta con F y enriquece la progresión. Puede iniciar una modulación o quedarse como simple préstamo." },
{ q:"La minorización se llama a veces 'cambio modal' porque:", opts:["Cambia el tempo","Transforma el modo del acorde (mayor → menor) — analogía con el cambio de modo de una escala","Utiliza dos armaduras","Cambia la métrica"], a:1, fb:"La minorización es un cambio de modo local: el acorde pasa del modo mayor al modo menor. Es análogo a pasar de una escala mayor a su paralela menor — pero a escala de un solo acorde." },
{ q:"V → Vm es más raro que I → Im porque:", opts:["V menor no existe","V menor pierde la sensible — Gm no tiene Si natural (sensible de C), debilitando la tensión cadencial","V menor está fuera de la tonalidad","V menor es demasiado grave"], a:1, fb:"Gm (Sol–Si♭–Ré) no tiene Si natural — la sensible de C se pierde. Gm tiene por tanto menos tensión cadencial que G o G7. V → Vm es un debilitamiento de la dominante — raro, pero utilizado para efectos específicos (ej: cadencia modal)." },
{ q:"La progresión Am–G–F–E7–Am en A menor ilustra:", opts:["Una minorización","Una mayorización del Vº grado — Em se convierte en E7 (mayor con 7ª) para crear la sensible G#","Una marcha armónica","Un pedal de dominante"], a:1, fb:"E7 (Mi–Sol#–Si–Ré) es la mayorización-funcionalización del Vº grado de A menor. En menor natural, el Vº sería Em (menor, sin G#). El menor armónico 'mayoriza' la dominante para crear la sensible." },
{ q:"La minorización puede crear una modulación hacia:", opts:["Únicamente el relativo menor","La tonalidad cuyo acorde minorizado se convierte en un grado funcional natural — frecuentemente la tonalidad una cuarta arriba","La misma tonalidad","Únicamente tonos lejanos"], a:1, fb:"La minorización de C (C→Cm) prepara Bb (Cm = IIm de Bb). En general, el acorde minorizado se convierte en el IIm de la nueva tonalidad — una cuarta arriba. Ej: D→Dm prepara C (Dm = IIm de C). Siempre una cuarta arriba." },
{ q:"¿Qué notación indica una minorización en un cifrado de acordes?", opts:["El acorde seguido de '7'","El acorde seguido de 'm' — ej: C se convierte en Cm","El acorde seguido de 'aug'","El acorde seguido de 'dim'"], a:1, fb:"La minorización de C se escribe Cm en el cifrado americano. La 'm' indica que la tercera está bajada un semitono. C = Do–Mi–Sol, Cm = Do–Mi♭–Sol." },
{ q:"En la progresión C–Cm–Bb–F, Cm inicia una modulación hacia:", opts:["F mayor","Bb mayor — Cm = IIm de Bb, prepara F7 (V de Bb) y luego Bb","G menor","C menor definitivamente"], a:1, fb:"Cm = IIm de Bb mayor. La progresión Cm–F7 sería SD–D en Bb, pero aquí tenemos Cm–Bb directamente. La modulación hacia Bb se inicia con la minorización de C." },
{ q:"La minorización del IVº grado (F → Fm en C) va seguida frecuentemente de:", opts:["G7 directamente","C (tónica) para una cadencia plagal menor","D7","Am"], a:1, fb:"La progresión C–Fm–C es una cadencia plagal menor — Fm reemplaza a F como subdominante. Es un préstamo muy expresivo. También se puede encadenar hacia G7: C–Fm–G7–C = SD prestada–D–T." },
{ q:"Un pedal armónico es:", opts:["Un acorde repetido sin cambiar","Una nota sostenida o repetida mientras las otras voces cambian de acordes","Un acorde de dominante fijo","Un ornamento melódico"], a:1, fb:"El pedal armónico es una nota mantenida (sostenida o repetida) en una voz mientras las armonías cambian a su alrededor. Puede pertenecer a los acordes que pasan o serles ajeno — creando entonces disonancias." },
{ q:"El pedal de tónica crea:", opts:["Tensión máxima","Estabilidad — ancla el centro tonal manteniendo la fundamental de la tónica","Una modulación","Una suspensión"], a:1, fb:"El pedal de tónica mantiene el Iº grado (Do en C) mientras la armonía evoluciona. Ancla el centro tonal — el oído nunca pierde el hilo de la tónica. Frecuentemente utilizado al inicio o al final de un movimiento." },
{ q:"El pedal de dominante prepara:", opts:["Una nueva tonalidad","La cadencia final — la dominante sostenida crea una tensión prolongada que amplifica la resolución sobre I","Un pedal de tónica","Un acorde napolitano"], a:1, fb:"El pedal de dominante mantiene Sol (en C) mientras los acordes cambian por encima. Esta tensión prolongada hace que la resolución final sobre C sea tanto más satisfactoria. Muy utilizado antes de las grandes cadencias." },
{ q:"El pedal doble mantiene simultáneamente:", opts:["Dos fundamentales cualesquiera","Los dos polos tonales — tónica y dominante (Do y Sol en C)","La tercera y la quinta","Dos dominantes secundarias"], a:1, fb:"El pedal doble mantiene simultáneamente I y V — Do y Sol en C. Ancla los dos polos fundamentales de la tonalidad, creando una base muy estable para armonías en movimiento por encima." },
{ q:"El pedal de soprano es característico de:", opts:["La música barroca únicamente","La música del siglo XIX y el impresionismo (Debussy, Ravel)","La fuga únicamente","El jazz moderno únicamente"], a:1, fb:"El pedal de soprano — nota sostenida en la voz superior — está particularmente desarrollado en el romanticismo y el impresionismo. Debussy lo utiliza abundantemente para crear efectos de suspensión y ambigüedad armónica." },
{ q:"Un pedal es 'ajeno' cuando:", opts:["Se toca fuerte","No forma parte del acorde que pasa por encima — crea una disonancia temporal","Es muy grave","Dura solo un compás"], a:1, fb:"Un pedal ajeno (o 'pedal note' en inglés) no forma parte del acorde en curso — crea una disonancia. Esta disonancia se resuelve cuando llega un acorde que contiene el pedal. El efecto de tensión es expresivo." },
{ q:"La progresión C–Am–F–G con Do sostenido en el bajo es un pedal de:", opts:["Dominante","Tónica — Do es el Iº grado de C, permanece en el bajo durante toda la progresión","Pedal doble","Pedal de soprano"], a:1, fb:"Do es la tónica de C mayor. Mantenido en el bajo durante Am, F y G (que no todos contienen Do como fundamental), crea un pedal de tónica. El efecto ancla C como centro durante la evolución armónica." },
];

const questionsDe: Question[] = [{ q:"Was ist eine musikalische Sequenz (Marche)?", opts:["Ein wiederholter Akkord","Ein melodisches oder harmonisches Motiv, das auf verschiedenen Stufen wiederholt wird — schrittweise transponiert","Eine Abfolge von vollkommenen Kadenzen","Ein Tempowechsel"], a:1, fb:"Eine Sequenz (Marche) ist ein Motiv, das auf verschiedenen Stufen wiederholt wird: das Motiv wird schrittweise 'weitergeschoben'. Pachelbels Kanon ist das klassische Beispiel einer diatonischen Sequenz." },
{ q:"Der Unterschied zwischen diatonischer Sequenz und harmonischer Sequenz ist:", opts:["Die diatonische Sequenz liegt tiefer","Die diatonische Sequenz bleibt in der Tonleiter (Intervalle angepasst), die harmonische Sequenz transponiert exakt (kann die Tonleiter verlassen)","Sie sind identisch","Die harmonische Sequenz verwendet ausschließlich Moll-Akkorde"], a:1, fb:"Diatonische Sequenz: das Motiv passt sich den Intervallen der Tonleiter an — man bleibt in der Tonart. Harmonische Sequenz: exakte Transposition der Intervalle — man verlässt die Tonleiter und moduliert." },
{ q:"Pachelbels Kanon ist ein Beispiel für:", opts:["Eine harmonische Sequenz","Eine diatonische Sequenz — das Motiv steigt stufenweise in D-Dur ab, ohne die Tonart zu verlassen","Eine Modulation durch Gemeinnote","Eine Dominantpedal"], a:1, fb:"Pachelbels Kanon verschiebt dasselbe harmonische Motiv stufenweise in D-Dur — das ist eine diatonische Sequenz. Die Intervalle passen sich leicht an, um in der Tonleiter zu bleiben." },
{ q:"Eine harmonische Sequenz moduliert, weil:", opts:["Sie verminderte Akkorde verwendet","Sie das Motiv mit exakten Intervallen transponiert — das zwingt zur Verwendung von Tönen außerhalb der Ausgangstonleiter","Sie das Tempo ändert","Sie die chromatische Tonleiter verwendet"], a:1, fb:"Die harmonische Sequenz bewahrt die exakten Intervalle des Motivs. Wenn das Motiv eine große Terz enthält, hat jede Transposition eine exakte große Terz — was tonleiterfremde Töne einführen kann." },
{ q:"Die Progression Gm–Fm–Ebm–Dbm ist eine Sequenz:", opts:["Diatonisch in G-Moll","Harmonisch — jeder Akkord steigt um einen Ton ab, gleicher Typ (Moll), verlässt die Tonleiter","Chromatisch","Kadenzierend"], a:1, fb:"Gm → Fm → Ebm → Dbm: jeder Moll-Akkord sinkt um einen Ganzton. Die Progression verlässt G-Moll nach Fm — das ist eine absteigende harmonische Sequenz in Ganztönen." },
{ q:"Die diatonische Sequenz in Chopins Étude op.10 Nr.3 bleibt in:", opts:["E-Moll","E-Dur — das Motiv wird stufenweise verschoben, ohne E-Dur zu verlassen","C-Dur","A-Moll"], a:1, fb:"Chopins Étude op.10 Nr.3 steht in E-Dur. Die diatonische Sequenz im A-Teil verschiebt das Motiv stufenweise ohne E-Dur zu verlassen. Chopin bringt mitunter leichte Varianten des Modells." },
{ q:"Die harmonische Sequenz ist ein Modulationsmittel, weil:", opts:["Sie sehr schnell ist","Jeder 'Schritt' der Sequenz als neue tonale Station wahrgenommen werden kann — die Spannung akkumuliert sich","Sie Kadenzen vermeidet","Sie ausschließlich Dur-Akkorde verwendet"], a:1, fb:"Jede exakte Transposition der harmonischen Sequenz führt neue Vorzeichen ein — jeder Schritt ist potenziell eine neue Tonart. Die Progression ist 'reisend': man entfernt sich schrittweise vom Ausgangspunkt." },
{ q:"In einer harmonischen Sequenz dient die vollkommene Kadenz am Ziel dazu:", opts:["Die Sequenz neu zu beginnen","Die neue Tonart zu bestätigen und zu verankern — Signal, dass die Reise endet","Eine falsche Fährte zu legen","Zur Ausgangstonart zurückzukehren"], a:1, fb:"Nach einer harmonischen Sequenz, die durch mehrere Tonarten geführt hat, bestätigt eine vollkommene Kadenz in der Zieltonart die Ankunft. Ohne sie bliebe man in der Mehrdeutigkeit." },
{ q:"Die absteigende harmonische Sequenz in Ganztönen Gm–Fm–Ebm–Dbm findet sich in:", opts:["Ausschließlich im Chaconne-Bass","Zahlreichen romantischen Stücken und Jazz — z.B. Misty, viele Balladen","Ausschließlich im Blues","Ausschließlich in barocken Fugen"], a:1, fb:"Die harmonische Abstieg in Ganztönen (Zyklus absteigender Sekunden) ist im Jazz und in der romantischen Popmusik allgegenwärtig. Sie erzeugt ein Gefühl des schrittweisen harmonischen 'Gleitens'." },
{ q:"Die Chaconne von Bach verwendet einen Ostinato-Bass, der ist:", opts:["Eine harmonische Sequenz","Eine diatonische Sequenz — der Bass steigt stufenweise in D-Moll ab","Ein Drehpunktakkord","Ein Dominantpedal"], a:1, fb:"Der Bass der Chaconne von Bach steigt in D-Moll stufenweise ab — D–C–Bb–A. Das ist eine diatonische Sequenz im Bass (Ostinato), keine harmonische Sequenz, die modulieren würde." },
{ q:"Schönberg unterscheidet tonale und melodische Sequenz, weil:", opts:["Es verschiedene Namen für dasselbe sind","Die tonale Sequenz die Intervalle der Tonleiter anpasst, die melodische Sequenz hingegen den melodischen Umriss selbst leicht verändern kann","Es keine Unterscheidung gibt","Die melodische Sequenz tiefer liegt"], a:1, fb:"Schönberg bemerkt, dass in einer tonalen (diatonischen) Sequenz nicht nur die Intervalle angepasst werden, sondern auch der melodische Umriss leicht variieren kann, um sich der Tonleiter anzupassen. Diese beiden Begriffe unterscheiden die harmonische und melodische Ebene der Anpassung." },
{ q:"Die Progression C–G–Am–Em–F–C–Dm–G ist eine Sequenz:", opts:["Harmonisch — sie verlässt C-Dur","Diatonisch — alle Akkorde gehören zu C-Dur","Chromatisch","Direkt"], a:1, fb:"C G Am Em F C Dm G: alle diese Akkorde sind diatonisch zu C-Dur. Die Progression ist eine diatonische Sequenz — das Motiv I–V wird auf VI–III, dann IV–I transponiert und bleibt in C." },
{ q:"Eine aufsteigende harmonische Sequenz in Halbtönen erzeugt:", opts:["Ein beruhigendes Gefühl","Eine intensive chromatische Spannung — jeder Schritt steigt um einen Halbton","Eine Blue-Progression","Einen Pedaleffekt"], a:1, fb:"Der chromatische Aufstieg in Halbtönen (z.B. Cm–C#m–Dm–D#m) erzeugt eine progressiv sehr intensive chromatische Spannung. Von Ravel, Chopin und vielen Komponisten für dramatische Effekte verwendet." },
{ q:"Die harmonische Sequenz durch absteigende Quinten ist:", opts:["Ausschließlich eine diatonische Sequenz","Dasselbe wie der diatonische Quintenzirkel — aber in exakter, modulierender Version","In der Praxis unmöglich","Ausschließlich barock"], a:1, fb:"Der harmonische Quintenzirkel transponiert das Motiv der Quinte bei jedem Schritt exakt. Bleibt man diatonisch, ist es der Quintenzirkel aus Kurs 3. Bewahrt man die exakten Intervalle, moduliert man — harmonische Sequenz." },
{ q:"Der klangliche Unterschied zwischen diatonischer und harmonischer Sequenz ist:", opts:["Keiner","Die diatonische Sequenz klingt 'innerhalb' der Tonart, die harmonische Sequenz erzeugt ein Gefühl des tonalen Treibens","Die harmonische Sequenz liegt tiefer","Die diatonische Sequenz ist schneller"], a:1, fb:"Die diatonische Sequenz bleibt im tonalen 'Zuhause' — das Ohr erkennt die Tonleiter. Die harmonische Sequenz 'treibt' — die exakten Intervalle erzeugen tonleiterfremde Töne und geben ein Gefühl des schrittweisen Reisens." },
{ q:"In der Étude op.10 Nr.3 wechselt Chopin diatonische Sequenz mit:", opts:["Chromatischer Sequenz","Harmonischer Sequenz an bestimmten Stellen — Beweis, dass beide Verfahren koexistieren","Basispedal","Neapolitanischem Akkord"], a:1, fb:"In der Étude op.10 Nr.3 verwendet Chopin hauptsächlich eine diatonische Sequenz, führt aber stellenweise exakte Transpositionenein (harmonische Sequenz) ein, um leichte tonale Abweichungen zu erzeugen." },
{ q:"Um eine harmonische Sequenz als Modulationsmittel zu verwenden, muss man:", opts:["Die Sequenz endlos wiederholen","Die Sequenz auf der neuen Tonart stoppen und diese durch eine vollkommene Kadenz bestätigen","Die erzeugten Vorzeichen ignorieren","Immer zur Ausgangstonart zurückkehren"], a:1, fb:"Die harmonische Sequenz führt bei jedem Schritt in eine neue Tonart. Wenn man das gewünschte Ziel erreicht, stoppt man die Sequenz und bestätigt die neue Tonart durch eine vollkommene Kadenz." },
{ q:"Das Muster I–V–VI–III–IV–I–II–V in C (Pachelbels Kanon) ist eine Sequenz:", opts:["Harmonisch — es moduliert nach G","Diatonisch — es bleibt in C und verschiebt das Motiv I–V auf verschiedene Stufen","Direkt — es springt zwischen Tonarten","Gemischt"], a:1, fb:"I–V: C–G. VI–III: Am–Em. IV–I: F–C. II–V: Dm–G. Alles bleibt in C-Dur. Die Sequenzstufen (I, VI, IV, II) sind der Ausgangspunkt des Motivs, das sich jedes Mal an die Tonleiter anpasst." },
{ q:"Die harmonische Sequenz in Ganztönen (Gm–Fm–Ebm) ist absteigend. Macht man sie aufsteigend:", opts:["Das ist nicht möglich","Erhält man Gm–Am–Bm — eine aufsteigende Sequenz in Ganztönen (oder in Halbtönen je nach gewähltem Intervall)","Sie wird diatonisch","Sie wird zum Pedal"], a:1, fb:"Eine harmonische Sequenz kann in beide Richtungen verlaufen. Gm–Am–Bm = aufsteigende Sequenz in Ganztönen. Cm–Db–Dm = aufsteigende Sequenz in Halbtönen. Die Richtung erzeugt verschiedene Ausdruckseffekte (aufsteigende Spannung vs. Abstieg)." },
{ q:"Die 'chromatische' Sequenz (in Halbtönen) ist eine Form von:", opts:["Diatonischer Sequenz","Harmonischer Sequenz — die exakten Halbtöne zwingen bei jedem Schritt, die Tonleiter zu verlassen","Ausschließlich tonaler Sequenz","Plagaler Sequenz"], a:1, fb:"Eine Sequenz in Halbtönen transponiert das Motiv jedes Mal um einen Halbton — gleiche exakte Intervalle. Das ist eine chromatische harmonische Sequenz. Jeder Schritt führt neue Vorzeichen ein." },
{ q:"Die Modulation durch Gemeinnote verwendet:", opts:["Einen beiden Tonarten gemeinsamen Akkord","Einen einzigen identischen Ton (Dreh-Note), der als Verbindung zwischen dem Ausgangsakkord und dem Zielakkord dient","Zwei gemeinsame Akkorde","Die künstliche Leittonsubstitution"], a:1, fb:"Die Modulation durch Gemeinnote verwendet nicht einen ganzen Akkord als Drehpunkt, sondern einen einzigen Ton, der beiden harmonischen Kontexten angehört. Dieser Ton wechselt seine Funktion — er 'gleitet' von einer Rolle zur anderen." },
{ q:"Bei der Modulation durch Gemeinnote liegt die Dreh-Note in der Regel:", opts:["Im Bass — als Pedaleffekt","Im Sopran — sie zieht die Aufmerksamkeit auf sich und leitet das Ohr","Im Tenor — die stabilste Stimme","Im Alt — Mittelstimme"], a:1, fb:"Die Dreh-Note wirkt am besten im Sopran, da sie dort am deutlichsten hörbar ist. Das Ohr folgt der Oberstimme — wenn sie unbeweglich bleibt, während sich die Harmonie darunter ändert, ist der Übergang fließend und wahrnehmbar." },
{ q:"Bei der Modulation von G nach Eb mit Sol als Gemeinnote:", opts:["Sol wird zur Terz von Eb-Dur (Sol ist die Terz von Eb = Eb–Sol–Bb)","Sol wird zur Grundtöne von Eb","Sol wird zur Leitnote von Eb","Sol gehört nicht zu Eb"], a:0, fb:"Sol ist die Terz von Eb-Dur (Eb–Sol–Bb). In G-Dur ist Sol die Tonika. Sol als Gemeinnote: Tonika von G → Terz von Eb. Dieselbe Tonhöhe wechselt ihre harmonische Rolle — fließende Modulation." },
{ q:"Die häufigsten Töne für eine Modulation durch Gemeinnote sind:", opts:["Grundton und Quinte","Terz, Septime, None und Tredezime","Ausschließlich die Leitnote","Die Töne des Dominantakkords"], a:1, fb:"Extensionstöne (Terz, Septime, None, Tredezime) werden am häufigsten als Gemeinnoten verwendet, da sie vielen Akkorden in verschiedenen Tonarten angehören." },
{ q:"Liegt die Gemeinnote im Bass statt im Sopran, ist der Effekt:", opts:["Identisch","Statischer — sie wirkt eher als Pedal denn als melodische Leittöne","Dramatischer","Schneller"], a:1, fb:"Eine Gemeinnote im Bass erzeugt einen Pedaleffekt — die Harmonie wechselt über einem unbeweglichen Bass. Im Sopran leitet sie das Ohr melodisch. Beide Effekte sind gültig, aber verschieden." },
{ q:"Die Modulation durch Gemeinnote wird verwendet von:", opts:["Ausschließlich Bach","Chopin, Liszt, Debussy und dem modernen Jazz — besonders für Modulationen in entfernte Tonarten","Ausschließlich Mozart","Ausschließlich dem Barock"], a:1, fb:"Diese Technik ist charakteristisch für die Romantik (Chopin, Liszt, Schubert) und den Impressionismus (Debussy). Im Jazz kann eine Dreh-Note die Terz oder Septime des neuen Akkords sein — Reharmonisierung." },
{ q:"Die Modulation durch Gemeinnote ermöglicht das Erreichen von:", opts:["Ausschließlich benachbarten Tonarten","Entfernten Tonarten auf fließende Weise — die Gemeinnote schafft eine unmerkliche Verbindung trotz der Distanz","Ausschließlich der parallelen Molltonart","Derselben Tonart (Tautologie)"], a:1, fb:"Die Modulation durch Gemeinnote ist besonders nützlich für entfernte Tonarten (Mediante, Terzbeziehungen) — ein diatonischer Drehpunktakkord wäre schwer zu finden, aber ein einziger Ton genügt." },
{ q:"Die Modulation zur Mediante (Tonart in einer Terzdistanz) verwendet oft:", opts:["Einen diatonischen Drehpunktakkord","Die Gemeinnote — die Terz des Ausgangsakkords wird zum Grundton oder zur Terz der neuen Tonart","Ausschließlich eine direkte Kadenz","Den Quintenzirkel"], a:1, fb:"Modulationen durch Terzen (Mediante) eignen sich ideal für die Gemeinnote: die Terz des Ausgangsakkords wird häufig zu einem strukturellen Ton der neuen Tonart. Z.B.: Sol = Terz von C → Tonika von G (klassische Modulation) oder Terz von Eb." },
{ q:"Die Progression G-Dur → Eb-Dur mit Sol im Sopran veranschaulicht:", opts:["Eine brutal direkte Modulation","Eine Modulation durch Gemeinnote: Sol = Tonika von G → Terz von Eb","Eine Tonikalisierung von Eb","Ein Tonikpedal"], a:1, fb:"Sol ist die Tonika von G. In Eb-Dur (Eb–Sol–Bb) ist Sol die Terz. Indem Sol im Sopran gehalten wird, während die Harmonie von G nach Eb gleitet, hört man denselben Ton in zwei verschiedenen Kontexten — sehr fließende Modulation." },
{ q:"Im Jazz besteht die Reharmonisierung durch Gemeinnote darin:", opts:["Einen anderen Akkord mit demselben Bass zu spielen","Eine wichtige Note (Terz oder Septime) des Originalakkords im neuen Ersatzakkord beizubehalten","Alle Akkorde zu transponieren","Die Melodie zu entfernen"], a:1, fb:"Bei der Jazz-Reharmonisierung ersetzt man einen Akkord und bewahrt dabei einen seiner strukturellen Töne (meist Terz oder Septime) im neuen Akkord. Die melodische Kontinuität verdeckt die harmonische Änderung." },
{ q:"Die Gemeinnote funktioniert besonders gut, wenn sie:", opts:["Auf einer schwachen Zählzeit liegt","Gehalten oder wiederholt wird — ihre Dauer gibt ihr Zeit, die Funktion ohne Bruch zu wechseln","Sehr kurz ist","Auf der schwächsten Zählzeit des Taktes liegt"], a:1, fb:"Eine Gemeinnote muss lang genug gehört werden, damit das Ohr sie im ersten Kontext identifiziert und dann im zweiten neu interpretiert. Ein zu kurzer Ton würde diese doppelte Wahrnehmung nicht ermöglichen." },
{ q:"Die Modulation durch Gemeinnote unterscheidet sich von der Modulation durch Drehpunktakkord, weil:", opts:["Der Drehpunktakkord dramatischer ist","Die Gemeinnote einen einzigen Ton als Verbindung verwendet (keinen ganzen Akkord) — subtiler, mehr für entfernte Tonarten geeignet","Sie identisch sind","Der Drehpunktakkord neuer ist"], a:1, fb:"Der Drehpunktakkord teilt einen ganzen Akkord zwischen zwei Tonarten — funktioniert gut für nahe Tonarten. Die Gemeinnote teilt eine einzelne Tonhöhe — flexibler, ermöglicht das fließende Erreichen sehr entfernter Tonarten." },
{ q:"Wenn E die Gemeinnote zwischen C-Dur (Terz) und A-Moll (Tonika) ist, kann man modulieren:", opts:["Ausschließlich von C nach Am","In beide Richtungen: C→Am (E = III von C = I von Am) oder Am→C (E = I von Am = III von C)","Ausschließlich mit G7","Ausschließlich in harmonischem Moll"], a:1, fb:"Eine Gemeinnote funktioniert in beide Richtungen. E = III von C und I von Am. Man kann also C→Am modulieren (E bleibt, Rolle ändert sich) oder Am→C (E bleibt, Rolle ändert sich in die andere Richtung). Gleicher Mechanismus, entgegengesetzte Richtungen." },
{ q:"Die Modulation durch Gemeinnote erzeugt ein Gefühl von:", opts:["Dramatischem Bruch","Unmerklichem Gleiten — das Ohr wird durch den gehaltenen Ton geführt, während die Harmonie diskret wechselt","Rhythmischer Beschleunigung","Intensiver chromatischer Instabilität"], a:1, fb:"Das ist die große Stärke dieser Technik: der harmonische Wechsel ist dank des gehaltenen Tons kaum wahrnehmbar. Das Ohr folgt dem Leitfaden der Gemeinnote und 'gleitet' natürlich in die neue Tonart." },
{ q:"Bei einer Modulation durch Gemeinnote — was 'bewegt sich' und was 'bleibt'?", opts:["Alles bewegt sich","Die Harmonie bewegt sich (die Akkorde wechseln), die Gemeinnote bleibt — der Leitfaden","Nichts bewegt sich — es ist ein Pedal","Die Melodie bleibt, alles andere bewegt sich"], a:1, fb:"Die Gemeinnote ist die Stabilität im Wandel: sie bleibt unbeweglich (oder wird wiederholt), während sich die gesamte Harmonie um sie herum verwandelt. Dieser Kontrast zwischen Stabilität und Bewegung erzeugt die Flüssigkeit." },
{ q:"Die Gemeinnote wird manchmal 'Drehnote' genannt, in Analogie zu:", opts:["Dem Drehpunktakkord","Dem harmonischen Pedal","Beiden — in beiden Fällen 'dreht' sich ein Element zwischen zwei funktionalen Kontexten","Dem neapolitanischen Akkord"], a:2, fb:"In Analogie zum Drehpunktakkord (ein ganzer Akkord dreht sich zwischen zwei Tonarten) ist die Gemeinnote eine 'Drehnote' — ein einzelner Ton, der zwischen zwei Kontexten dreht. Die Logik ist identisch, der Maßstab verschieden." },
{ q:"Die Minorisation eines Akkords besteht darin:", opts:["Ihn ohne Änderung des tonalen Kontexts in Moll zu spielen","Die große Terz um einen Halbton abzusenken, um den Akkord zu einem Moll-Akkord zu machen — ihn oft in eine Brücke zur neuen Tonart umwandelnd","Ihn um einen Halbton zu transponieren","Ihn in Umkehrung zu spielen"], a:1, fb:"Die Minorisation senkt die Terz eines Dur-Akkords ab, um ihn moll zu machen. Z.B.: C (Do–E–Sol) → Cm (Do–Eb–Sol). Dieser neue Moll-Akkord kann in einer anderen Tonart reinterpretiert werden." },
{ q:"Der Ausdruckseffekt der Minorisation ist:", opts:["Freude","Plötzliche Melancholie — das Absenken der Terz erzeugt einen emotionalen Übergang ins Dunkel","Rhythmische Spannung","Tonale Klarheit"], a:1, fb:"Die Minorisation erzeugt einen unmittelbaren emotionalen Übergang — die kleine Terz bringt eine melancholische Farbe, die mit dem vorangehenden Dur-Akkord kontrastiert. Es ist einer der ausdrucksstärksten Effekte der tonalen Harmonik." },
{ q:"In der Progression C → Cm → F7 → Bb ist Cm:", opts:["Eine Anleihe aus C-Moll","Die Minorisation von C, reinterpretiert als II von Bb-Dur — sie leitet die Modulation nach Bb ein","Eine Tonikalisierung von Bb","Ein neapolitanischer Akkord"], a:1, fb:"C (I von C) → Cm (Minorisation, minorisierte I) → Cm reinterpretiert als IIm von Bb → F7 (V von Bb) → Bb (I von Bb). Die Minorisation von C verwandelt ihn in IIm von Bb — Modulation von C nach Bb." },
{ q:"Die Modulation durch Minorisation von C nach Bb funktioniert, weil:", opts:["C und Bb dieselbe Tonart haben","Cm (Do–Eb–Sol) die II. Stufe von Bb-Dur ist (Bb–Do–Re–Eb–Fa–Sol–La). Cm reinterpretiert sich natürlich in Bb.","Cm die Dominante von Bb ist","C und Bb eine Quinte voneinander entfernt sind"], a:1, fb:"Cm = Do–Eb–Sol. In Bb-Dur ist die II. Stufe = Cm. Die Minorisation von C (C→Cm) verwandelt ihn in IIm von Bb, das natürlich F7 (V von Bb) dann Bb vorbereitet. Elegant und ökonomisch." },
{ q:"Die Majorisation ist die umgekehrte Operation der Minorisation:", opts:["Falsch — die Minorisation ist unumkehrbar","Richtig — man hebt die kleine Terz um einen Halbton an, um einen Moll-Akkord zu einem Dur-Akkord zu machen","Falsch — beide sind identisch","Richtig — aber die Majorisation ist viel häufiger"], a:1, fb:"Die Majorisation (Moll → Dur) ist die Umkehrung der Minorisation. Sie ist seltener, existiert aber — z.B.: Am → A (Dur) kann eine Tonikalisierung oder Modulation einleiten. Die Minorisation bleibt ausdrucksmäßig häufiger." },
{ q:"Die Progression I → Im ist ein Beispiel für:", opts:["Direkte Modulation","Minorisation der Tonika — sehr ausdrucksstark, oft in Codas","Ausschließlich Anleihe aus der gleichnamigen Molltonart","Dominantpedal"], a:1, fb:"I → Im ist eine Minorisation der Tonika — C → Cm. Es ist einer der ausdrucksstärksten Übergänge: die Tonika selbst verdunkelt sich. Sehr verwendet in romantischen Codas und melancholischen Schlüssen." },
{ q:"IV → IVm (z.B. F → Fm in C-Dur) ist:", opts:["Ein neapolitanischer Akkord","Eine klassische Anleihe der Romantik — die Minorisation der Subdominante","Eine Tonikalisierung von Fm","Eine Modulation nach C-Moll"], a:1, fb:"F → Fm = Minorisation der IV. Stufe. Es ist eine der häufigsten Anleihen der Romantik. Die dunkle Farbe von Fm kontrastiert mit F und bereichert die Progression. Kann eine Modulation einleiten oder eine einfache Anleihe bleiben." },
{ q:"Die Minorisation wird manchmal als 'Modalwechsel' bezeichnet, weil:", opts:["Sie das Tempo ändert","Sie den Modus des Akkords transformiert (Dur → Moll) — Analogie zum Wechsel des Modus einer Tonleiter","Sie zwei Tonartvorzeichnungen verwendet","Sie die Metrik ändert"], a:1, fb:"Die Minorisation ist ein lokaler Moduswechsel: der Akkord wechselt vom Dur- in den Moll-Modus. Das ist analog zum Übergang von einer Dur-Tonleiter zu ihrer parallelen Moll-Tonleiter — aber auf der Ebene eines einzelnen Akkords." },
{ q:"V → Vm ist seltener als I → Im, weil:", opts:["V-Moll nicht existiert","V-Moll die Leitnote verliert — Gm hat kein natürliches H (Leitnote von C), was die Kadenzzugspannung schwächt","V-Moll außerhalb der Tonart liegt","V-Moll zu tief liegt"], a:1, fb:"Gm (Sol–Bb–Re) hat kein natürliches H — die Leitnote von C ist verloren. Gm hat daher weniger Kadenzzugspannung als G oder G7. V → Vm ist eine Abschwächung der Dominante — selten, aber für spezifische Effekte verwendet (z.B. modale Kadenz)." },
{ q:"Die Progression Am–G–F–E7–Am in A-Moll veranschaulicht:", opts:["Eine Minorisation","Eine Majorisation der V. Stufe — Em wird zu E7 (Dur mit Septime), um die Leitnote G# zu erzeugen","Eine harmonische Sequenz","Ein Dominantpedal"], a:1, fb:"E7 (E–G#–H–D) ist die Majorisation-Funktionalisierung der V. Stufe in A-Moll. In der natürlichen Molltonart wäre die V. Stufe Em (Moll, ohne G#). Das harmonische Moll 'majorisiert' die Dominante, um die Leitnote zu erzeugen." },
{ q:"Die Minorisation kann eine Modulation einleiten nach:", opts:["Ausschließlich der parallelen Molltonart","Die Tonart, in der der minorisierte Akkord eine natürliche funktionale Stufe wird — oft die Tonart eine Quarte höher","Derselben Tonart","Ausschließlich entfernten Tonarten"], a:1, fb:"Die Minorisation von C (C→Cm) bereitet Bb vor (Cm = IIm von Bb). Im Allgemeinen wird der minorisierte Akkord zur IIm der neuen Tonart — eine Quarte höher. Z.B.: D→Dm bereitet C vor (Dm = IIm von C). Immer eine Quarte höher." },
{ q:"Welche Notation zeigt eine Minorisation in einer Akkordchiffre?", opts:["Der Akkord gefolgt von '7'","Der Akkord gefolgt von 'm' — z.B. C wird zu Cm","Der Akkord gefolgt von 'aug'","Der Akkord gefolgt von 'dim'"], a:1, fb:"Die Minorisation von C wird im amerikanischen Chiffrierungssystem als Cm geschrieben. Das 'm' zeigt an, dass die Terz um einen Halbton erniedrigt wurde. C = Do–Mi–Sol, Cm = Do–Mi♭–Sol." },
];

const questionsIt: Question[] = [{ q:"Cos'è una marcia musicale?", opts:["Un accordo ripetuto","Un motivo melodico o armonico ripetuto su gradi diversi — trasposto progressivamente","Una successione di cadenze perfette","Un cambiamento di tempo"], a:1, fb:"Una marcia (o sequenza) è un motivo ripetuto su gradi diversi: si sposta il motivo come si 'cammina' per tappe. Il Canone di Pachelbel è l'esempio classico di marcia diatonica." },
{ q:"La differenza tra marcia diatonica e marcia armonica è:", opts:["La marcia diatonica è più grave","La marcia diatonica resta nella scala (intervalli adattati), la marcia armonica traspone esattamente (può uscire dalla scala)","Sono identiche","La marcia armonica utilizza solo accordi minori"], a:1, fb:"Marcia diatonica: il motivo si adatta agli intervalli della scala — si rimane nella tonalità. Marcia armonica: trasposizione esatta degli intervalli — si esce dalla scala e si modula." },
{ q:"Il Canone di Pachelbel è un esempio di:", opts:["Marcia armonica","Marcia diatonica — il motivo scende per gradi restando in D maggiore","Modulazione per nota comune","Pedale di dominante"], a:1, fb:"Il Canone di Pachelbel sposta lo stesso motivo armonico per gradi successivi in D maggiore — è una marcia diatonica. Gli intervalli si adattano leggermente per restare nella scala." },
{ q:"Una marcia armonica modula perché:", opts:["Utilizza accordi diminuiti","Traspone il motivo con intervalli esatti — questo costringe a usare note estranee alla scala di partenza","Cambia il tempo","Utilizza la scala cromatica"], a:1, fb:"La marcia armonica preserva gli intervalli esatti del motivo. Se il motivo contiene una terza maggiore, ogni trasposizione avrà una terza maggiore esatta — il che può introdurre note estranee alla scala." },
{ q:"La progressione Gm–Fm–Ebm–Dbm è una marcia:", opts:["Diatonica in G minore","Armonica — ogni accordo scende di un tono, stesso tipo (minore), uscendo dalla scala","Cromatica","Cadenzale"], a:1, fb:"Gm → Fm → Ebm → Dbm: ogni accordo minore scende di un tono intero. La progressione esce da G minore dopo Fm — è una marcia armonica discendente per toni." },
{ q:"La marcia diatonica dell'Étude op.10 n°3 di Chopin resta in:", opts:["E minore","E maggiore — il motivo si sposta per gradi restando nella scala","C maggiore","A minore"], a:1, fb:"L'Étude op.10 n°3 di Chopin è in E maggiore. La marcia diatonica della sezione A sposta il motivo per gradi senza uscire da E maggiore. Chopin vi apporta talvolta lievi varianti del modello." },
{ q:"La marcia armonica è uno strumento di modulazione perché:", opts:["È molto rapida","Ogni 'tappa' della marcia può essere percepita come una nuova sosta tonale — la tensione si accumula","Evita le cadenze","Utilizza solo accordi maggiori"], a:1, fb:"Ogni trasposizione esatta della marcia armonica introduce nuove alterazioni — ogni tappa è potenzialmente una nuova tonalità. La progressione è 'viaggiatrice': ci si allontana progressivamente dal punto di partenza." },
{ q:"In una marcia armonica, la cadenza perfetta all'arrivo serve a:", opts:["Ricominciare la marcia","Confermare e ancorare la nuova tonalità — segnale che il viaggio si conclude","Creare una falsa pista","Tornare alla tonalità di partenza"], a:1, fb:"Dopo una marcia armonica che ha viaggiato attraverso diverse tonalità, una cadenza perfetta nella tonalità finale conferma l'arrivo. Senza di essa, si rimarrebbe nell'ambiguità." },
{ q:"La marcia armonica discendente per toni Gm–Fm–Ebm–Dbm si trova in:", opts:["Solo nel basso di ciaccona","Molti brani romantici e jazz — es: Misty, molte ballate","Solo nel blues","Solo nelle fughe barocche"], a:1, fb:"La discesa armonica per toni (ciclo di seconde discendenti) è onnipresente nel jazz e nella musica pop romantica. Crea una sensazione di 'scivolamento' armonico progressivo." },
{ q:"La Ciaccona di Bach utilizza un basso ostinato che è:", opts:["Una marcia armonica","Una marcia diatonica — il basso scende per gradi restando in D minore","Un accordo pivot","Un pedale di dominante"], a:1, fb:"Il basso della Ciaccona di Bach scende per gradi congiunti in D minore — D–C–Bb–A. È una marcia diatonica al basso (ostinato), non una marcia armonica che modulerebbe." },
{ q:"Schoenberg distingue marcia tonale e marcia melodica perché:", opts:["Sono nomi diversi per la stessa cosa","La marcia tonale adatta gli intervalli alla scala, la marcia melodica può modificare leggermente il disegno melodico stesso","Non c'è distinzione","La marcia melodica è più grave"], a:1, fb:"Schoenberg nota che in una marcia tonale (diatonica), gli intervalli si adattano ma anche il disegno melodico può variare leggermente per adattarsi alla scala. Queste due nozioni distinguono il livello armonico e melodico dell'adattamento." },
{ q:"La progressione C–G–Am–Em–F–C–Dm–G è una marcia:", opts:["Armonica — esce da C maggiore","Diatonica — tutti gli accordi appartengono a C maggiore","Cromatica","Diretta"], a:1, fb:"C G Am Em F C Dm G: tutti questi accordi sono diatonici a C maggiore. La progressione è una marcia diatonica — il motivo I–V si traspone su VI–III poi IV–I, restando in C." },
{ q:"Una marcia armonica ascendente per semitoni crea:", opts:["Una sensazione rasserenante","Una tensione cromatica intensa — ogni tappa sale di un semitono","Una progressione blues","Un effetto di pedale"], a:1, fb:"La salita cromatica per semitoni (es: Cm–C#m–Dm–D#m) crea una tensione cromatica progressiva molto intensa. Utilizzata da Ravel, Chopin e molti compositori per effetti drammatici." },
{ q:"La marcia armonica per ciclo di quinte discendenti è:", opts:["Solo una marcia diatonica","La stessa cosa del ciclo delle quinte diatoniche — ma in versione esatta, modulante","Impossibile in pratica","Esclusivamente barocca"], a:1, fb:"Il ciclo delle quinte armoniche traspone esattamente il motivo di quinta ad ogni tappa. Se si resta diatonico, è il ciclo visto nel corso 3. Se si preservano gli intervalli esatti, si modula — marcia armonica." },
{ q:"La differenza sonora tra marcia diatonica e marcia armonica è:", opts:["Nessuna","La marcia diatonica suona 'all'interno' della tonalità, la marcia armonica crea una sensazione di deriva tonale","La marcia armonica è più grave","La marcia diatonica è più rapida"], a:1, fb:"La marcia diatonica resta nel 'paese' tonale — l'orecchio riconosce la scala. La marcia armonica 'deriva' — gli intervalli esatti creano note estranee, dando una sensazione di viaggio progressivo." },
{ q:"Nell'Étude op.10 n°3, Chopin alterna marcia diatonica e:", opts:["Marcia cromatica","Marcia armonica in certi punti — prova che i due procedimenti coesistono","Pedale di basso","Accordo napoletano"], a:1, fb:"Nell'Étude op.10 n°3, Chopin utilizza principalmente una marcia diatonica ma introduce in certi punti trasposizioni esatte (marcia armonica) per creare lievi derive tonali." },
{ q:"Per utilizzare una marcia armonica come strumento di modulazione, si:", opts:["Ripete la marcia indefinitamente","Ferma la marcia sulla nuova tonalità e la conferma con una cadenza perfetta","Ignora le alterazioni create","Torna sempre alla tonalità di partenza"], a:1, fb:"La marcia armonica trasporta verso una nuova tonalità ad ogni tappa. Quando si arriva alla destinazione desiderata, si ferma la marcia e si conferma la nuova tonalità con una cadenza perfetta." },
{ q:"Il pattern I–V–VI–III–IV–I–II–V in C (Canone di Pachelbel) è una marcia:", opts:["Armonica — modula in G","Diatonica — resta in C spostando il motivo I–V su gradi diversi","Diretta — salta tra tonalità","Mista"], a:1, fb:"I–V: C–G. VI–III: Am–Em. IV–I: F–C. II–V: Dm–G. Tutto resta in C maggiore. I gradi della marcia (I, VI, IV, II) sono il punto di partenza del motivo, che si adatta ogni volta alla scala." },
{ q:"La marcia armonica per toni (Gm–Fm–Ebm) è discendente. Se la si rende ascendente:", opts:["Non è possibile","Si ottiene Gm–Am–Bm — una marcia ascendente per toni (o per semitoni secondo l'intervallo scelto)","Diventa diatonica","Diventa un pedale"], a:1, fb:"Una marcia armonica può andare in entrambe le direzioni. Gm–Am–Bm = marcia ascendente per toni. Cm–Db–Dm = marcia ascendente per semitoni. La direzione crea effetti espressivi diversi (tensione ascendente vs discesa)." },
{ q:"La marcia 'cromatica' (per semitoni) è una forma di marcia:", opts:["Diatonica","Armonica — i semitoni esatti costringono a uscire dalla scala ad ogni tappa","Solo tonale","Plagale"], a:1, fb:"Una marcia per semitoni traspone il motivo di un semitono ogni volta — stessi intervalli esatti. È una marcia armonica cromatica. Ogni tappa introduce nuove alterazioni." },
{ q:"La modulazione per nota comune utilizza:", opts:["Un accordo comune alle due tonalità","Una sola nota identica (nota pivot) che serve da legame tra l'accordo di partenza e l'accordo di arrivo","Due accordi comuni","La sensibile artificiale"], a:1, fb:"La modulazione per nota comune non utilizza un accordo intero come pivot, ma una sola nota che appartiene ai due contesti armonici. Questa nota cambia funzione — 'scivola' da un ruolo a un altro." },
{ q:"Nella modulazione per nota comune, la nota pivot è generalmente:", opts:["Al basso — effetto di pedale","Al soprano — attira l'attenzione e guida l'orecchio","Al tenore — voce più stabile","Al contralto — voce intermedia"], a:1, fb:"La nota pivot funziona meglio al soprano perché è la più udibile. L'orecchio segue la linea superiore — quando rimane immobile mentre l'armonia cambia sotto di essa, lo scivolamento è fluido e percettibile." },
{ q:"Modulando da G verso Eb con Sol come nota comune:", opts:["Sol diventa la terza di Eb maggiore (Sol è la terza di Eb = Mi♭–Sol–Si♭)","Sol diventa la fondamentale di Eb","Sol diventa la sensibile di Eb","Sol non appartiene a Eb"], a:0, fb:"Sol è la terza di Eb maggiore (Mi♭–Sol–Si♭). In G maggiore, Sol è la tonica. Sol come nota comune: tonica di G → terza di Eb. La stessa altezza cambia ruolo armonico — modulazione fluida." },
{ q:"Le note più comuni per una modulazione per nota comune sono:", opts:["La fondamentale e la quinta","La terza, la settima, la nona e la tredicesima","Solo la sensibile","Le note dell'accordo di dominante"], a:1, fb:"Le note di estensione (terza, settima, nona, tredicesima) sono le più utilizzate come note comuni poiché appartengono a molti accordi in tonalità diverse." },
{ q:"Se la nota comune è al basso invece che al soprano, l'effetto è:", opts:["Identico","Più statico — agisce come un pedale piuttosto che come una nota melodica conduttrice","Più drammatico","Più rapido"], a:1, fb:"Una nota comune al basso crea un effetto di pedale — l'armonia cambia sopra un basso immobile. Al soprano, guida l'orecchio melodicamente. Entrambi gli effetti sono validi ma diversi." },
{ q:"La modulazione per nota comune è utilizzata da:", opts:["Solo Bach","Chopin, Liszt, Debussy e il jazz moderno — particolarmente per le modulazioni verso toni lontani","Solo Mozart","Solo il barocco"], a:1, fb:"Questa tecnica è caratteristica del romanticismo (Chopin, Liszt, Schubert) e dell'impressionismo (Debussy). Nel jazz, una nota pivot può essere la terza o la settima del nuovo accordo — riarmonizzazione." },
{ q:"La modulazione per nota comune permette di raggiungere:", opts:["Solo i toni vicini","Tonalità lontane in modo fluido — la nota comune crea un legame impercettibile nonostante la distanza","Solo il relativo minore","La stessa tonalità (tautologia)"], a:1, fb:"La modulazione per nota comune è particolarmente utile per le tonalità lontane (mediante, toni a distanza di terza) — l'accordo pivot diatonico sarebbe difficile da trovare, ma una sola nota è sufficiente." },
{ q:"La modulazione verso la mediante (tonalità a una terza) utilizza spesso:", opts:["Un accordo pivot diatonico","La nota comune — la terza dell'accordo di partenza diventa la fondamentale o la terza della nuova tonalità","Solo una cadenza diretta","Il ciclo delle quinte"], a:1, fb:"Le modulazioni per terze (mediante) sono ideali per la nota comune: la terza dell'accordo di partenza diventa spesso una nota strutturale della nuova tonalità. Es: Sol = terza di C → tonica di G (modulazione classica) o terza di Eb." },
{ q:"La progressione G maggiore → Mi♭ maggiore con Sol al soprano illustra:", opts:["Una modulazione diretta brusca","Una modulazione per nota comune: Sol = tonica di G → terza di Eb","Una tonicizzazione di Eb","Un pedale di tonica"], a:1, fb:"Sol è la tonica di G. In Eb maggiore (Mi♭–Sol–Si♭), Sol è la terza. Mantenendo Sol al soprano mentre l'armonia scivola da G verso Eb, si ascolta la stessa nota in due contesti diversi — modulazione molto fluida." },
{ q:"Nel jazz, la riarmonizzazione per nota comune consiste nel:", opts:["Suonare un accordo diverso con lo stesso basso","Mantenere una nota importante (terza o settima) dell'accordo originale nel nuovo accordo sostitutivo","Trasporre tutti gli accordi","Sopprimere la melodia"], a:1, fb:"Nella riarmonizzazione jazz, si sostituisce un accordo conservando una delle sue note strutturali (spesso la terza o la settima) nel nuovo accordo. La continuità melodica maschera il cambiamento armonico." },
{ q:"La nota comune funziona particolarmente bene quando è:", opts:["Su un tempo debole","Tenuta o ripetuta — la sua durata le dà il tempo di cambiare funzione senza rottura","Molto breve","Sul tempo più debole della misura"], a:1, fb:"Una nota comune deve essere ascoltata abbastanza a lungo perché l'orecchio la identifichi nel primo contesto, poi la reinterpreti nel secondo. Una nota troppo breve non permetterebbe questa doppia percezione." },
{ q:"La modulazione per nota comune differisce dalla modulazione per accordo pivot perché:", opts:["L'accordo pivot è più drammatico","La nota comune utilizza un solo suono come legame (non un accordo intero) — più sottile, più usata per i toni lontani","Sono identiche","L'accordo pivot è più recente"], a:1, fb:"L'accordo pivot condivide un accordo intero tra due tonalità — funziona bene per i toni vicini. La nota comune condivide una sola altezza — più flessibile, permette di raggiungere toni molto lontani in modo fluido." },
{ q:"Se Mi è la nota comune tra C maggiore (terza) e A minore (tonica), si può modulare:", opts:["Solo da C verso Am","In entrambe le direzioni: C→Am (Mi = III di C = I di Am) o Am→C (Mi = I di Am = III di C)","Solo usando G7","Solo in minore armonico"], a:1, fb:"Una nota comune funziona in entrambe le direzioni. Mi = III di C e I di Am. Si può quindi modulare C→Am (Mi resta, il ruolo cambia) o Am→C (Mi resta, il ruolo cambia nell'altro senso). Stesso meccanismo, direzioni opposte." },
{ q:"La modulazione per nota comune crea una sensazione di:", opts:["Rottura drammatica","Scivolamento impercettibile — l'orecchio è guidato dalla nota tenuta mentre l'armonia cambia discretamente","Accelerazione ritmica","Intensa instabilità cromatica"], a:1, fb:"È la grande forza di questa tecnica: il cambiamento armonico è quasi impercettibile grazie alla nota mantenuta. L'orecchio segue il filo conduttore della nota comune e 'scivola' naturalmente verso la nuova tonalità." },
{ q:"In una modulazione per nota comune, cosa 'si muove' e cosa 'resta'?", opts:["Tutto si muove","L'armonia si muove (gli accordi cambiano), la nota comune resta — il filo conduttore","Niente si muove — è un pedale","La melodia resta, tutto il resto si muove"], a:1, fb:"La nota comune è la stabilità nel cambiamento: resta immobile (o ripetuta) mentre tutta l'armonia intorno a essa si trasforma. È questo contrasto tra stabilità e movimento che crea la fluidità." },
{ q:"La nota comune è talvolta chiamata 'nota pivot' per analogia con:", opts:["L'accordo pivot","Il pedale armonico","Entrambi — in entrambi i casi, un elemento 'ruota' tra due contesti funzionali","L'accordo napoletano"], a:2, fb:"Per analogia con l'accordo pivot (un accordo intero che ruota tra due tonalità), la nota comune è una 'nota pivot' — un solo suono che ruota tra due contesti. La logica è identica, la scala è diversa." },
{ q:"La minorizzazione di un accordo consiste nel:", opts:["Suonarlo in minore senza alterare il contesto tonale","Abbassare la terza maggiore di un semitono per rendere l'accordo minore — trasformandolo spesso in ponte verso una nuova tonalità","Trasporlo di un semitono","Suonarlo in rivolto"], a:1, fb:"La minorizzazione abbassa la terza di un accordo maggiore per renderlo minore. Es: C (Do–Mi–Sol) → Cm (Do–Mi♭–Sol). Questo nuovo accordo minore può essere reinterpretato in un'altra tonalità." },
{ q:"L'effetto espressivo della minorizzazione è:", opts:["Gioia","Una malinconia improvvisa — l'abbassamento della terza crea uno scivolamento emotivo verso l'ombra","Tensione ritmica","Chiarezza tonale"], a:1, fb:"La minorizzazione crea uno scivolamento emotivo immediato — la terza minore apporta un colore malinconico che contrasta con l'accordo maggiore precedente. È uno degli effetti più espressivi dell'armonia tonale." },
{ q:"Nella progressione C → Cm → F7 → Bb, Cm è:", opts:["Un prestito a C minore","La minorizzazione di C, reinterpretata come II di Bb maggiore — avvia la modulazione verso Bb","Una tonicizzazione di Bb","Un accordo napoletano"], a:1, fb:"C (I di C) → Cm (minorizzazione, I minorizzato) → Cm reinterpretato come IIm di Bb → F7 (V di Bb) → Bb (I di Bb). La minorizzazione di C lo trasforma in IIm di Bb — modulazione da C verso Bb." },
{ q:"La modulazione per minorizzazione da C verso Bb funziona perché:", opts:["C e Bb hanno la stessa armatura","Cm (Do–Mi♭–Sol) è il II° grado di Bb maggiore (Si♭–Do–Re–Mi♭–Fa–Sol–La). Cm si reinterpreta naturalmente in Bb.","Cm è la dominante di Bb","C e Bb sono a una quinta l'uno dall'altro"], a:1, fb:"Cm = Do–Mi♭–Sol. In Bb maggiore, il II° grado = Cm. La minorizzazione di C (C→Cm) lo trasforma in IIm di Bb, che prepara naturalmente F7 (V di Bb) poi Bb. Elegante ed economico." },
{ q:"La maggiorizzazione è l'operazione inversa della minorizzazione:", opts:["Falso — la minorizzazione è irreversibile","Vero — si alza la terza minore di un semitono per rendere un accordo minore maggiore","Falso — le due sono identiche","Vero — ma la maggiorizzazione è molto più frequente"], a:1, fb:"La maggiorizzazione (minore → maggiore) è l'inverso della minorizzazione. È meno comune ma esiste — es: Am → A (maggiore) può avviare una tonicizzazione o una modulazione. La minorizzazione resta espressivamente più frequente." },
{ q:"La progressione I → Im è un esempio di:", opts:["Modulazione diretta","Minorizzazione della tonica — molto espressiva, spesso nelle code","Solo prestito all'omonimo","Pedale di dominante"], a:1, fb:"I → Im è una minorizzazione della tonica — C → Cm. È una delle transizioni più espressive: la tonica stessa si oscura. Molto usata nelle code romantiche e nelle conclusioni malinconiche." },
{ q:"IV → IVm (es: F → Fm in C maggiore) è:", opts:["Un accordo napoletano","Un prestito classico del romanticismo — la minorizzazione della sottodominante","Una tonicizzazione di Fm","Una modulazione in C minore"], a:1, fb:"F → Fm = minorizzazione del IV° grado. È uno dei prestiti più frequenti del romanticismo. Il colore scuro di Fm contrasta con F e arricchisce la progressione. Può avviare una modulazione o restare un semplice prestito." },
{ q:"La minorizzazione è talvolta chiamata 'cambiamento modale' perché:", opts:["Cambia il tempo","Trasforma il modo dell'accordo (maggiore → minore) — analogia con il cambiamento di modo di una scala","Utilizza due armature","Cambia la metrica"], a:1, fb:"La minorizzazione è un cambiamento di modo locale: l'accordo passa dal modo maggiore al modo minore. È analogo al passare da una scala maggiore alla sua parallela minore — ma a livello di un singolo accordo." },
{ q:"V → Vm è più raro di I → Im perché:", opts:["V minore non esiste","V minore perde la sensibile — Gm non ha Si naturale (sensibile di C), indebolendo la tensione cadenzale","V minore è fuori tonalità","V minore è troppo grave"], a:1, fb:"Gm (Sol–Si♭–Re) non ha Si naturale — la sensibile di C è persa. Gm ha quindi meno tensione cadenzale di G o G7. V → Vm è un indebolimento della dominante — raro, ma usato per effetti specifici (es: cadenza modale)." },
{ q:"La progressione Am–G–F–E7–Am in A minore illustra:", opts:["Una minorizzazione","Una maggiorizzazione del V° grado — Em diventa E7 (maggiore con 7a) per creare la sensibile G#","Una marcia armonica","Un pedale di dominante"], a:1, fb:"E7 (Mi–Sol#–Si–Re) è la maggiorizzazione-funzionalizzazione del V° grado di A minore. In minore naturale, il V° sarebbe Em (minore, senza G#). Il minore armonico 'maggiorizza' la dominante per creare la sensibile." },
{ q:"La minorizzazione può creare una modulazione verso:", opts:["Solo il relativo minore","La tonalità di cui l'accordo minorizzato diventa un grado funzionale naturale — spesso la tonalità una quarta sopra","La stessa tonalità","Solo toni lontani"], a:1, fb:"La minorizzazione di C (C→Cm) prepara Bb (Cm = IIm di Bb). In generale, l'accordo minorizzato diventa il IIm della nuova tonalità — una quarta sopra. Es: D→Dm prepara C (Dm = IIm di C). Sempre una quarta sopra." },
{ q:"Quale notazione indica una minorizzazione in una cifratura degli accordi?", opts:["L'accordo seguito da '7'","L'accordo seguito da 'm' — es: C diventa Cm","L'accordo seguito da 'aug'","L'accordo seguito da 'dim'"], a:1, fb:"La minorizzazione di C si scrive Cm nella cifratura americana. La 'm' indica che la terza è abbassata di un semitono. C = Do–Mi–Sol, Cm = Do–Mi♭–Sol." },
{ q:"Nella progressione C–Cm–Bb–F, Cm avvia una modulazione verso:", opts:["F maggiore","Bb maggiore — Cm = IIm di Bb, prepara F7 (V di Bb) poi Bb","G minore","C minore definitivamente"], a:1, fb:"Cm = IIm di Bb maggiore. La progressione Cm–F7 sarebbe SD–D in Bb, ma qui abbiamo Cm–Bb direttamente. La modulazione verso Bb è avviata dalla minorizzazione di C." },
{ q:"La minorizzazione del IV° grado (F → Fm in C) è spesso seguita da:", opts:["G7 direttamente","C (tonica) per una cadenza plagale minore","D7","Am"], a:1, fb:"La progressione C–Fm–C è una cadenza plagale minore — Fm sostituisce F come sottodominante. È un prestito molto espressivo. Si può anche proseguire verso G7: C–Fm–G7–C = SD prestata–D–T." },
{ q:"Un pedale armonico è:", opts:["Un accordo ripetuto senza cambiare","Una nota tenuta o ripetuta mentre le altre voci cambiano accordo","Un accordo di dominante fisso","Un ornamento melodico"], a:1, fb:"Il pedale armonico è una nota mantenuta (tenuta o ripetuta) in una voce mentre le armonie cambiano intorno a essa. Può appartenere agli accordi che passano o esserne estranea — creando in tal caso dissonanze." },
{ q:"Il pedale di tonica crea:", opts:["Massima tensione","Stabilità — ancorizza il centro tonale mantenendo la fondamentale della tonica","Una modulazione","Una sospensione"], a:1, fb:"Il pedale di tonica mantiene il I° grado (Do in C) mentre l'armonia evolve. Ancorizza il centro tonale — l'orecchio non perde mai il filo della tonica. Spesso usato all'inizio o alla fine di un movimento." },
{ q:"Il pedale di dominante prepara:", opts:["Una nuova tonalità","La cadenza finale — la dominante tenuta crea una tensione prolungata che amplifica la risoluzione su I","Un pedale di tonica","Un accordo napoletano"], a:1, fb:"Il pedale di dominante mantiene Sol (in C) mentre gli accordi cambiano sopra. Questa tensione prolungata rende la risoluzione finale su C tanto più soddisfacente. Molto usato prima delle grandi cadenze." },
{ q:"Il doppio pedale mantiene simultaneamente:", opts:["Due fondamentali qualsiasi","I due poli tonali — tonica e dominante (Do e Sol in C)","La terza e la quinta","Due dominanti secondarie"], a:1, fb:"Il doppio pedale mantiene simultaneamente I e V — Do e Sol in C. Ancorizza i due poli fondamentali della tonalità, creando una base molto stabile per armonie mobili al di sopra." },
{ q:"Il pedale di soprano è caratteristico di:", opts:["Solo la musica barocca","La musica del XIX secolo e l'impressionismo (Debussy, Ravel)","Solo la fuga","Solo il jazz moderno"], a:1, fb:"Il pedale di soprano — nota tenuta nella voce superiore — è particolarmente sviluppato nel romanticismo e nell'impressionismo. Debussy lo utilizza abbondantemente per creare effetti di sospensione e ambiguità armonica." },
{ q:"Un pedale è 'estraneo' quando:", opts:["È suonato forte","Non fa parte dell'accordo che passa sopra — crea una dissonanza temporanea","È molto grave","Dura una sola misura"], a:1, fb:"Un pedale estraneo (o 'pedal note' in inglese) non fa parte dell'accordo in corso — crea una dissonanza. Questa dissonanza si risolve quando arriva un accordo contenente il pedale. L'effetto di tensione è espressivo." },
{ q:"La progressione C–Am–F–G con Do tenuto al basso è un pedale di:", opts:["Dominante","Tonica — Do è il I° grado di C, resta al basso durante tutta la progressione","Doppio pedale","Pedale di soprano"], a:1, fb:"Do è la tonica di C maggiore. Mantenuto al basso durante Am, F e G (che non contengono tutti Do come fondamentale), crea un pedale di tonica. L'effetto ancorizza C come centro durante l'evoluzione armonica." },
{ q:"La progressione Dm–G7–C con Sol tenuto al basso è un pedale di:", opts:["Tonica","Dominante — Sol è il V° grado di C. Rimane immobile mentre Dm e G7 passano","Doppio pedale","Pedale di soprano"], a:1, fb:"Sol è la dominante di C. Mantenuto al basso durante Dm e G7, crea un pedale di dominante. La tensione è massima — Sol risolve su Do solo alla fine. Molto usato prima delle grandi cadenze." },
];

const questionsPt: Question[] = [{ q:"O que é uma marcha musical?", opts:["Um acorde repetido","Um motivo melódico ou harmônico repetido em diferentes graus — transposto progressivamente","Uma sucessão de cadências perfeitas","Uma mudança de andamento"], a:1, fb:"Uma marcha (ou sequência) é um motivo repetido em diferentes graus: desloca-se o motivo como se estivesse 'marchando' em etapas. O Cânone de Pachelbel é o exemplo clássico de marcha diatônica." },
{ q:"A diferença entre marcha diatônica e marcha harmônica é:", opts:["A marcha diatônica é mais grave","A marcha diatônica permanece na escala (intervalos ajustados), a marcha harmônica transpõe exatamente (podendo sair da escala)","Elas são idênticas","A marcha harmônica utiliza apenas acordes menores"], a:1, fb:"Marcha diatônica: o motivo se adapta aos intervalos da escala — permanece na tonalidade. Marcha harmônica: transposição exata dos intervalos — sai da escala e modula." },
{ q:"O Cânone de Pachelbel é um exemplo de:", opts:["Marcha harmônica","Marcha diatônica — o motivo desce por graus permanecendo em D maior","Modulação por nota comum","Pedal de dominante"], a:1, fb:"O Cânone de Pachelbel desloca o mesmo motivo harmônico por graus sucessivos em D maior — é uma marcha diatônica. Os intervalos se ajustam levemente para permanecer na escala." },
{ q:"Uma marcha harmônica modula porque:", opts:["Utiliza acordes diminutos","Transpõe o motivo com intervalos exatos — isso obriga a usar notas fora da escala de partida","Muda o andamento","Utiliza a escala cromática"], a:1, fb:"A marcha harmônica preserva os intervalos exatos do motivo. Se o motivo contém uma terça maior, cada transposição terá uma terça maior exata — o que pode introduzir notas estranhas à escala." },
{ q:"A progressão Gm–Fm–Ebm–Dbm é uma marcha:", opts:["Diatônica em G menor","Harmônica — cada acorde desce um tom, mesmo tipo (menor), saindo da escala","Cromática","Cadencial"], a:1, fb:"Gm → Fm → Ebm → Dbm: cada acorde menor desce um tom inteiro. A progressão sai de G menor após Fm — é uma marcha harmônica descendente por tons." },
{ q:"A marcha diatônica do Estudo op.10 nº3 de Chopin permanece em:", opts:["E menor","E maior — o motivo se desloca por graus permanecendo na escala","C maior","A menor"], a:1, fb:"O Estudo op.10 nº3 de Chopin está em E maior. A marcha diatônica da seção A desloca o motivo por graus sem sair de E maior. Chopin introduz às vezes leves variantes do modelo." },
{ q:"A marcha harmônica é uma ferramenta de modulação porque:", opts:["É muito rápida","Cada 'etapa' da marcha pode ser percebida como uma nova escala tonal — a tensão se acumula","Evita as cadências","Utiliza apenas acordes maiores"], a:1, fb:"Cada transposição exata da marcha harmônica introduz novas alterações — cada etapa é potencialmente uma nova tonalidade. A progressão é 'viajante': afasta-se progressivamente do ponto de partida." },
{ q:"Em uma marcha harmônica, a cadência perfeita na chegada serve para:", opts:["Recomeçar a marcha","Confirmar e ancorar a nova tonalidade — sinal de que a viagem termina","Criar uma pista falsa","Retornar à tonalidade de partida"], a:1, fb:"Após uma marcha harmônica que percorre várias tonalidades, uma cadência perfeita na tonalidade final confirma a chegada. Sem ela, permaneceria a ambiguidade." },
{ q:"A marcha harmônica descendente por tons Gm–Fm–Ebm–Dbm aparece em:", opts:["Apenas no baixo de chacona","Muitas peças românticas e jazz — ex: Misty, numerosas baladas","Apenas no blues","Apenas em fugas barrocas"], a:1, fb:"A descida harmônica por tons (ciclo de segundas descendentes) está onipresente no jazz e na música pop romântica. Cria uma sensação de 'deslizamento' harmônico progressivo." },
{ q:"A Chacona de Bach utiliza um baixo ostinato que é:", opts:["Uma marcha harmônica","Uma marcha diatônica — o baixo desce por graus permanecendo em D menor","Um acorde pivô","Um pedal de dominante"], a:1, fb:"O baixo da Chacona de Bach desce por graus conjuntos em D menor — D–C–Bb–A. É uma marcha diatônica no baixo (ostinato), não uma marcha harmônica que modularia." },
{ q:"Schoenberg distingue marcha tonal e marcha melódica porque:", opts:["São nomes diferentes para a mesma coisa","A marcha tonal adapta os intervalos à escala, a marcha melódica pode modificar levemente o próprio desenho melódico","Não há distinção","A marcha melódica é mais grave"], a:1, fb:"Schoenberg observa que em uma marcha tonal (diatônica), os intervalos se ajustam mas também o desenho melódico pode variar levemente para se adaptar à escala. Essas duas noções distinguem o nível harmônico e melódico da adaptação." },
{ q:"A progressão C–G–Am–Em–F–C–Dm–G é uma marcha:", opts:["Harmônica — ela sai de C maior","Diatônica — todos os acordes pertencem a C maior","Cromática","Direta"], a:1, fb:"C G Am Em F C Dm G: todos esses acordes são diatônicos em C maior. A progressão é uma marcha diatônica — o motivo I–V se transpõe sobre VI–III depois IV–I, permanecendo em C." },
{ q:"Uma marcha harmônica ascendente por semitons cria:", opts:["Uma sensação apaziguadora","Uma tensão cromática intensa — cada etapa sobe um semitom","Uma progressão blues","Um efeito de pedal"], a:1, fb:"A subida cromática por semitons (ex: Cm–C#m–Dm–D#m) cria uma tensão cromática progressiva muito intensa. Utilizada por Ravel, Chopin e muitos compositores para efeitos dramáticos." },
{ q:"A marcha harmônica por ciclo de quintas descendentes é:", opts:["Apenas uma marcha diatônica","A mesma coisa que o ciclo das quintas diatônicas — mas em versão exata, modulante","Impossível na prática","Exclusivamente barroca"], a:1, fb:"O ciclo das quintas harmônicas transpõe exatamente o motivo de quinta a cada etapa. Se permanece diatônico, é o ciclo visto no curso 3. Se os intervalos são preservados exatamente, modula — marcha harmônica." },
{ q:"A diferença sonora entre marcha diatônica e marcha harmônica é:", opts:["Nenhuma","A marcha diatônica soa 'dentro' da tonalidade, a marcha harmônica cria uma sensação de deriva tonal","A marcha harmônica é mais grave","A marcha diatônica é mais rápida"], a:1, fb:"A marcha diatônica permanece no 'país' tonal — o ouvido reconhece a escala. A marcha harmônica 'deriva' — os intervalos exatos criam notas estranhas, dando uma sensação de viagem progressiva." },
{ q:"No Estudo op.10 nº3, Chopin alterna marcha diatônica e:", opts:["Marcha cromática","Marcha harmônica em certos trechos — prova de que os dois procedimentos coexistem","Pedal de baixo","Acorde napolitano"], a:1, fb:"No Estudo op.10 nº3, Chopin utiliza principalmente uma marcha diatônica mas introduz em alguns trechos transposições exatas (marcha harmônica) para criar leves derivas tonais." },
{ q:"Para utilizar uma marcha harmônica como ferramenta de modulação:", opts:["Repete-se a marcha indefinidamente","Para-se a marcha na nova tonalidade e confirma-se por uma cadência perfeita","Ignoram-se as alterações criadas","Retorna-se sempre à tonalidade de partida"], a:1, fb:"A marcha harmônica transporta para uma nova tonalidade a cada etapa. Quando se chega ao destino desejado, para-se a marcha e confirma-se a nova tonalidade por uma cadência perfeita." },
{ q:"O padrão I–V–VI–III–IV–I–II–V em C (Cânone de Pachelbel) é uma marcha:", opts:["Harmônica — modula em G","Diatônica — permanece em C deslocando o motivo I–V sobre diferentes graus","Direta — salta entre tonalidades","Mista"], a:1, fb:"I–V: C–G. VI–III: Am–Em. IV–I: F–C. II–V: Dm–G. Tudo permanece em C maior. Os graus da marcha (I, VI, IV, II) são o ponto de partida do motivo, que se adapta a cada vez à escala." },
{ q:"A marcha harmônica por tons (Gm–Fm–Ebm) é descendente. Se tornada ascendente:", opts:["Não é possível","Obtém-se Gm–Am–Bm — uma marcha ascendente por tons (ou por semitons conforme o intervalo escolhido)","Ela se torna diatônica","Ela se torna um pedal"], a:1, fb:"Uma marcha harmônica pode ir nos dois sentidos. Gm–Am–Bm = marcha ascendente por tons. Cm–Db–Dm = marcha ascendente por semitons. A direção cria efeitos expressivos diferentes (tensão ascendente vs descida)." },
{ q:"A marcha 'cromática' (por semitons) é uma forma de marcha:", opts:["Diatônica","Harmônica — os semitons exatos obrigam a sair da escala a cada etapa","Apenas tonal","Plagal"], a:1, fb:"Uma marcha por semitons transpõe o motivo de um semitom a cada vez — mesmos intervalos exatos. É uma marcha harmônica cromática. Cada etapa introduz novas alterações." },
{ q:"A modulação por nota comum utiliza:", opts:["Um acorde comum às duas tonalidades","Uma única nota idêntica (nota pivô) que serve de elo entre o acorde de partida e o acorde de chegada","Dois acordes comuns","A sensível artificial"], a:1, fb:"A modulação por nota comum não utiliza um acorde inteiro como pivô, mas uma única nota que pertence aos dois contextos harmônicos. Essa nota muda de função — ela 'desliza' de um papel para outro." },
{ q:"Na modulação por nota comum, a nota pivô geralmente está:", opts:["No baixo — efeito de pedal","No soprano — ela atrai a atenção e guia o ouvido","No tenor — voz mais estável","No contralto — voz intermediária"], a:1, fb:"A nota pivô funciona melhor no soprano pois é a mais audível. O ouvido segue a linha superior — quando ela permanece imóvel enquanto a harmonia muda abaixo, o deslizamento é fluido e perceptível." },
{ q:"Ao modular de G para Eb com Sol como nota comum:", opts:["Sol se torna a terça de Eb maior (Sol é a terça de Eb = Mi♭–Sol–Si♭)","Sol se torna a fundamental de Eb","Sol se torna a sensível de Eb","Sol não pertence a Eb"], a:0, fb:"Sol é a terça de Eb maior (Mi♭–Sol–Si♭). Em G maior, Sol é a tônica. Sol como nota comum: tônica de G → terça de Eb. A mesma altura muda de papel harmônico — modulação fluida." },
{ q:"As notas mais comuns para uma modulação por nota comum são:", opts:["A fundamental e a quinta","A terça, a sétima, a nona e a décima terceira","Apenas a sensível","As notas do acorde de dominante"], a:1, fb:"As notas de extensão (terça, sétima, nona, décima terceira) são as mais utilizadas como notas comuns pois pertencem a muitos acordes em diferentes tonalidades." },
{ q:"Se a nota comum está no baixo em vez do soprano, o efeito é:", opts:["Idêntico","Mais estático — ela age como um pedal em vez de uma nota melódica condutora","Mais dramático","Mais rápido"], a:1, fb:"Uma nota comum no baixo cria um efeito de pedal — a harmonia muda acima de um baixo imóvel. No soprano, ela guia o ouvido melodicamente. Os dois efeitos são válidos mas diferentes." },
{ q:"A modulação por nota comum é utilizada por:", opts:["Apenas Bach","Chopin, Liszt, Debussy e o jazz moderno — particularmente para modulações em tons distantes","Apenas Mozart","Apenas o barroco"], a:1, fb:"Essa técnica é característica do romantismo (Chopin, Liszt, Schubert) e do impressionismo (Debussy). No jazz, uma nota pivô pode ser a terça ou a sétima do novo acorde — reharmonização." },
{ q:"A modulação por nota comum permite alcançar:", opts:["Apenas tons vizinhos","Tonalidades distantes de maneira fluida — a nota comum cria um elo imperceptível apesar da distância","Apenas o relativo menor","A mesma tonalidade (tautologia)"], a:1, fb:"A modulação por nota comum é particularmente útil para tonalidades distantes (mediantes, tons à distância de terça) — o acorde pivô diatônico seria difícil de encontrar, mas uma única nota é suficiente." },
{ q:"A modulação para a mediante (tonalidade a uma terça) frequentemente utiliza:", opts:["Um acorde pivô diatônico","A nota comum — a terça do acorde de partida se torna a fundamental ou a terça da nova tonalidade","Apenas uma cadência direta","O ciclo das quintas"], a:1, fb:"As modulações por terças (mediantes) são ideais para a nota comum: a terça do acorde de partida frequentemente se torna uma nota estrutural da nova tonalidade. Ex: Sol = terça de C → tônica de G (modulação clássica) ou terça de Eb." },
{ q:"A progressão G maior → Mi♭ maior com Sol no soprano ilustra:", opts:["Uma modulação direta abrupta","Uma modulação por nota comum: Sol = tônica de G → terça de Eb","Uma tonicização de Eb","Um pedal de tônica"], a:1, fb:"Sol é a tônica de G. Em Eb maior (Mi♭–Sol–Si♭), Sol é a terça. Mantendo Sol no soprano enquanto a harmonia desliza de G para Eb, ouve-se a mesma nota em dois contextos diferentes — modulação muito fluida." },
{ q:"No jazz, a reharmonização por nota comum consiste em:", opts:["Tocar um acorde diferente com o mesmo baixo","Manter uma nota importante (terça ou sétima) do acorde original no novo acorde substituto","Transpor todos os acordes","Suprimir a melodia"], a:1, fb:"Na reharmonização jazz, substitui-se um acorde conservando uma de suas notas estruturais (geralmente a terça ou a sétima) no novo acorde. A continuidade melódica mascara a mudança harmônica." },
{ q:"A nota comum funciona particularmente bem quando está:", opts:["Em um tempo fraco","Sustentada ou repetida — sua duração lhe dá tempo para mudar de função sem ruptura","Muito curta","No tempo mais fraco do compasso"], a:1, fb:"Uma nota comum deve ser ouvida por tempo suficiente para que o ouvido a identifique no primeiro contexto e depois a reinterprete no segundo. Uma nota muito curta não permitiria essa dupla percepção." },
{ q:"A modulação por nota comum difere da modulação por acorde pivô porque:", opts:["O acorde pivô é mais dramático","A nota comum utiliza um único som como elo (não um acorde inteiro) — mais sutil, mais usada para tons distantes","Elas são idênticas","O acorde pivô é mais recente"], a:1, fb:"O acorde pivô compartilha um acorde inteiro entre duas tonalidades — funciona bem para tons próximos. A nota comum compartilha uma única altura — mais flexível, permite alcançar tons muito distantes de maneira fluida." },
{ q:"Se Mi é a nota comum entre C maior (terça) e A menor (tônica), pode-se modular:", opts:["Apenas de C para Am","Nos dois sentidos: C→Am (Mi = III de C = I de Am) ou Am→C (Mi = I de Am = III de C)","Apenas usando G7","Apenas em menor harmônico"], a:1, fb:"Uma nota comum funciona nas duas direções. Mi = III de C e I de Am. Pode-se portanto modular C→Am (Mi permanece, papel muda) ou Am→C (Mi permanece, papel muda no outro sentido). Mesmo mecanismo, direções opostas." },
{ q:"A modulação por nota comum cria uma sensação de:", opts:["Ruptura dramática","Deslizamento imperceptível — o ouvido é guiado pela nota sustentada enquanto a harmonia muda discretamente","Aceleração rítmica","Instabilidade cromática intensa"], a:1, fb:"Essa é a grande força dessa técnica: a mudança harmônica é quase imperceptível graças à nota mantida. O ouvido segue o fio condutor da nota comum e 'desliza' naturalmente para a nova tonalidade." },
{ q:"Em uma modulação por nota comum, o que 'se move' e o que 'permanece'?", opts:["Tudo se move","A harmonia se move (os acordes mudam), a nota comum permanece — o fio condutor","Nada se move — é um pedal","A melodia permanece, todo o resto se move"], a:1, fb:"A nota comum é a estabilidade na mudança: ela permanece imóvel (ou repetida) enquanto toda a harmonia ao redor se transforma. É esse contraste entre estabilidade e movimento que cria a fluidez." },
{ q:"A nota comum é às vezes chamada de 'nota pivô' por analogia com:", opts:["O acorde pivô","O pedal harmônico","Os dois — em ambos os casos, um elemento 'pivota' entre dois contextos funcionais","O acorde napolitano"], a:2, fb:"Por analogia com o acorde pivô (um acorde inteiro pivotando entre duas tonalidades), a nota comum é uma 'nota pivô' — um único som que pivota entre dois contextos. A lógica é idêntica, a escala é diferente." },
{ q:"A minorização de um acorde consiste em:", opts:["Tocá-lo em menor sem alterar o contexto tonal","Abaixar a terça maior um semitom para tornar o acorde menor — transformando-o frequentemente em ponte para uma nova tonalidade","Transpô-lo um semitom","Tocá-lo em inversão"], a:1, fb:"A minorização abaixa a terça de um acorde maior para torná-lo menor. Ex: C (Do–Mi–Sol) → Cm (Do–Mi♭–Sol). Esse novo acorde menor pode ser reinterpretado em outra tonalidade." },
{ q:"O efeito expressivo da minorização é:", opts:["Alegria","Uma melancolia súbita — o abaixamento da terça cria um deslizamento emocional para a sombra","Tensão rítmica","Clareza tonal"], a:1, fb:"A minorização cria um deslizamento emocional imediato — a terça menor traz uma cor melancólica que contrasta com o acorde maior precedente. É um dos efeitos mais expressivos da harmonia tonal." },
{ q:"Na progressão C → Cm → F7 → Bb, Cm é:", opts:["Um empréstimo de C menor","A minorização de C, reinterpretada como II de Bb maior — ela inicia a modulação para Bb","Uma tonicização de Bb","Um acorde napolitano"], a:1, fb:"C (I de C) → Cm (minorização, I minorizado) → Cm reinterpretado como IIm de Bb → F7 (V de Bb) → Bb (I de Bb). A minorização de C o transforma em IIm de Bb — modulação de C para Bb." },
{ q:"A modulação por minorização de C para Bb funciona porque:", opts:["C e Bb têm a mesma armadura","Cm (Do–Mi♭–Sol) é o IIº grau de Bb maior (Si♭–Do–Ré–Mi♭–Fá–Sol–Lá). Cm se reinterpreta naturalmente em Bb.","Cm é a dominante de Bb","C e Bb estão à quinta um do outro"], a:1, fb:"Cm = Do–Mi♭–Sol. Em Bb maior, o IIº grau = Cm. A minorização de C (C→Cm) o transforma em IIm de Bb, que prepara naturalmente F7 (V de Bb) depois Bb. Elegante e econômico." },
{ q:"A majorização é a operação inversa da minorização:", opts:["Falso — a minorização é irreversível","Verdadeiro — eleva-se a terça menor um semitom para tornar um acorde menor em maior","Falso — as duas são idênticas","Verdadeiro — mas a majorização é muito mais frequente"], a:1, fb:"A majorização (menor → maior) é o inverso da minorização. É menos comum mas existe — ex: Am → A (maior) pode iniciar uma tonicização ou uma modulação. A minorização permanece mais frequente expressivamente." },
{ q:"A progressão I → Im é um exemplo de:", opts:["Modulação direta","Minorização da tônica — muito expressiva, frequentemente nas codas","Apenas empréstimo do homônimo","Pedal de dominante"], a:1, fb:"I → Im é uma minorização da tônica — C → Cm. É uma das transições mais expressivas: a própria tônica se escurece. Muito usada em codas românticas e conclusões melancólicas." },
{ q:"IV → IVm (ex: F → Fm em C maior) é:", opts:["Um acorde napolitano","Um empréstimo clássico do romantismo — a minorização da subdominante","Uma tonicização de Fm","Uma modulação em C menor"], a:1, fb:"F → Fm = minorização do IVº grau. É um dos empréstimos mais frequentes do romantismo. A cor sombria do Fm contrasta com F e enriquece a progressão. Pode iniciar uma modulação ou permanecer como simples empréstimo." },
{ q:"A minorização é às vezes chamada de 'mudança modal' porque:", opts:["Ela muda o andamento","Ela transforma o modo do acorde (maior → menor) — analogia com a mudança de modo de uma escala","Ela utiliza duas armaduras","Ela muda a métrica"], a:1, fb:"A minorização é uma mudança de modo local: o acorde passa do modo maior para o modo menor. É análogo a passar de uma escala maior para sua paralela menor — mas na escala de um único acorde." },
{ q:"V → Vm é mais raro do que I → Im porque:", opts:["V menor não existe","V menor perde a sensível — Gm não tem Si natural (sensível de C), enfraquecendo a tensão cadencial","V menor está fora da tonalidade","V menor é muito grave"], a:1, fb:"Gm (Sol–Si♭–Ré) não tem Si natural — a sensível de C é perdida. Gm tem portanto menos tensão cadencial do que G ou G7. V → Vm é um enfraquecimento da dominante — raro, mas usado para efeitos específicos (ex: cadência modal)." },
{ q:"A progressão Am–G–F–E7–Am em A menor ilustra:", opts:["Uma minorização","Uma majorização do Vº grau — Em se torna E7 (maior com 7ª) para criar a sensível G#","Uma marcha harmônica","Um pedal de dominante"], a:1, fb:"E7 (Mi–Sol#–Si–Ré) é a majorização-funcionalização do Vº grau de A menor. Em menor natural, o Vº seria Em (menor, sem G#). O menor harmônico 'majoriza' a dominante para criar a sensível." },
{ q:"A minorização pode criar uma modulação para:", opts:["Apenas o relativo menor","A tonalidade da qual o acorde minorizado se torna um grau funcional natural — frequentemente a tonalidade uma quarta acima","A mesma tonalidade","Apenas tons distantes"], a:1, fb:"A minorização de C (C→Cm) prepara Bb (Cm = IIm de Bb). Em geral, o acorde minorizado se torna o IIm da nova tonalidade — uma quarta acima. Ex: D→Dm prepara C (Dm = IIm de C). Sempre uma quarta acima." },
{ q:"Qual notação indica uma minorização em uma cifragem de acordes?", opts:["O acorde seguido de '7'","O acorde seguido de 'm' — ex: C se torna Cm","O acorde seguido de 'aug'","O acorde seguido de 'dim'"], a:1, fb:"A minorização de C se escreve Cm na cifragem americana. O 'm' indica que a terça foi abaixada um semitom. C = Do–Mi–Sol, Cm = Do–Mi♭–Sol." },
{ q:"Na progressão C–Cm–Bb–F, Cm inicia uma modulação para:", opts:["F maior","Bb maior — Cm = IIm de Bb, prepara F7 (V de Bb) depois Bb","G menor","C menor definitivamente"], a:1, fb:"Cm = IIm de Bb maior. A progressão Cm–F7 seria SD–D em Bb, mas aqui temos Cm–Bb diretamente. A modulação para Bb é iniciada pela minorização de C." },
{ q:"A minorização do IVº grau (F → Fm em C) é frequentemente seguida de:", opts:["G7 diretamente","C (tônica) para uma cadência plagal menor","D7","Am"], a:1, fb:"A progressão C–Fm–C é uma cadência plagal menor — Fm substitui F como subdominante. É um empréstimo muito expressivo. Pode-se também encadear para G7: C–Fm–G7–C = SD emprestada–D–T." },
{ q:"Um pedal harmônico é:", opts:["Um acorde repetido sem mudança","Uma nota sustentada ou repetida enquanto as outras vozes mudam de acordes","Um acorde de dominante fixo","Um ornamento melódico"], a:1, fb:"O pedal harmônico é uma nota mantida (sustentada ou repetida) em uma voz enquanto as harmonias mudam ao redor dela. Pode pertencer aos acordes que passam ou ser estranha a eles — criando então dissonâncias." },
{ q:"O pedal de tônica cria:", opts:["Tensão máxima","Estabilidade — ele ancora o centro tonal mantendo a fundamental da tônica","Uma modulação","Uma suspensão"], a:1, fb:"O pedal de tônica mantém o Iº grau (Do em C) enquanto a harmonia evolui. Ele ancora o centro tonal — o ouvido nunca perde o fio da tônica. Frequentemente usado no início ou final de um movimento." },
{ q:"O pedal de dominante prepara:", opts:["Uma nova tonalidade","A cadência final — a dominante sustentada cria uma tensão prolongada que amplifica a resolução sobre I","Um pedal de tônica","Um acorde napolitano"], a:1, fb:"O pedal de dominante mantém Sol (em C) enquanto os acordes mudam acima. Essa tensão prolongada torna a resolução final sobre C ainda mais satisfatória. Muito usado antes das grandes cadências." },
{ q:"O pedal duplo mantém simultaneamente:", opts:["Duas fundamentais quaisquer","Os dois polos tonais — tônica e dominante (Do e Sol em C)","A terça e a quinta","Duas dominantes secundárias"], a:1, fb:"O pedal duplo mantém simultaneamente I e V — Do e Sol em C. Ele ancora os dois polos fundamentais da tonalidade, criando uma base muito estável para harmonias moventes acima." },
{ q:"O pedal de soprano é característico de:", opts:["Apenas a música barroca","A música do século XIX e o impressionismo (Debussy, Ravel)","Apenas a fuga","Apenas o jazz moderno"], a:1, fb:"O pedal de soprano — nota sustentada na voz superior — é particularmente desenvolvido no romantismo e no impressionismo. Debussy o utiliza abundantemente para criar efeitos de suspensão e ambiguidade harmônica." },
{ q:"Um pedal é 'estranho' quando:", opts:["É tocado forte","Não faz parte do acorde que passa acima — ele cria uma dissonância temporária","É muito grave","Dura apenas um compasso"], a:1, fb:"Um pedal estranho não faz parte do acorde em curso — ele cria uma dissonância. Essa dissonância é resolvida quando um acorde contendo o pedal chega. O efeito de tensão é expressivo." },
{ q:"A progressão C–Am–F–G com Do sustentado no baixo é um pedal de:", opts:["Dominante","Tônica — Do é o Iº grau de C, permanece no baixo durante toda a progressão","Pedal duplo","Pedal de soprano"], a:1, fb:"Do é a tônica de C maior. Mantido no baixo durante Am, F e G (que não contêm todos Do como fundamental), ele cria um pedal de tônica. O efeito ancora C como centro durante a evolução harmônica." },
{ q:"A progressão Dm–G7–C com Sol sustentado no baixo é um pedal de:", opts:["Tônica","Dominante — Sol é o Vº grau de C. Permanece imóvel enquanto Dm e G7 passam","Pedal duplo","Pedal de soprano"], a:1, fb:"Sol é a dominante de C. Mantido no baixo durante Dm e G7, ele cria um pedal de dominante. A tensão é máxima — Sol só resolve sobre Do no final. Muito usado antes das grandes cadências." },
];

